import type { Drill } from "./types";

// Public service / early drills, keyed by module slug — 25 per module.
// Front-line public servant: counter clerk, junior civil servant, constable,
// soldier, postal or municipal worker. Merged into course.ts.
export const PUBLICSERVICE_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-gov-early-01","level":"early","profession":"publicservice","title":"The buried incident in the shift report","scenario":"You're a constable finishing a quiet night shift with one real event: at 02:40 you found the pharmacy on King Street unlocked and secured it with the keyholder. Your draft report walks through the whole shift chronologically before mentioning it.","task":"Write a 1-2 sentence report opening that leads with the incident.","tips":["First sentence: what happened, where, and the outcome.","The uneventful hours are background, not the headline.","A supervisor skimming ten reports should catch this one immediately."],"focus":["structure","clarity"],"placeholder":"At 02:40 I found the King Street pharmacy unlocked; premises searched, secured with keyholder, no entry gained."},
    {"id":"lead-gov-early-02","level":"early","profession":"publicservice","title":"The radio request that wanders","scenario":"You're on foot patrol and need a traffic unit at Main and 5th, where a stalled truck is blocking the intersection at school pickup time. Your instinct is to describe how you came across it before saying what you need.","task":"Say (or write) a one-sentence radio request that leads with what you need and where.","tips":["Need and location in the first breath.","How you found it can wait for the report.","Dispatch acts on the ask, not the story."],"focus":["clarity","concision"],"placeholder":"Requesting a traffic unit at Main and 5th —"},
    {"id":"lead-gov-early-03","level":"early","profession":"publicservice","title":"The broken terminal email","scenario":"You work the licensing counter. The card terminal has been down since 09:00, you're turning away anyone without cash, and only IT can fix it. Your draft email to the service desk opens with two paragraphs about this morning's queue.","task":"Write a 2-3 sentence email that puts the request and the impact in the first sentence.","tips":["Lead with what you need: a technician, today.","State the public impact in numbers if you can.","Backstory about the morning is support, kept short."],"focus":["clarity","impact"],"placeholder":"The card terminal at counter 2 has been down since 09:00 — we need a technician today."},
    {"id":"lead-gov-early-04","level":"early","profession":"publicservice","title":"The resupply request up the chain","scenario":"You're a private and your section is down to one day of radio batteries with a 48-hour field exercise starting tomorrow. Your draft message to the section commander starts by explaining how the batteries were stored.","task":"Write a 1-2 sentence request that leads with what you need and by when.","tips":["The ask first: quantity, item, deadline.","How you got here comes after, in one clause.","Make it impossible to miss the shortfall."],"focus":["clarity","precision"],"placeholder":"Request 12 radio batteries before 06:00 tomorrow —"},
    {"id":"lead-gov-early-05","level":"early","profession":"publicservice","title":"The dog on the route","scenario":"You're a postal carrier. A large dog at 42 Elm ran loose at you this morning, so you skipped that block and deliveries are suspended until it's resolved. Your note to your supervisor starts with the weather and the route so far.","task":"Write a 2-sentence note that leads with the suspension and why.","tips":["Headline: deliveries stopped at 42 Elm block, loose dog.","Then the one action you need from them.","Safety issues never go at the bottom."],"focus":["clarity","impact"]},
    {"id":"lead-gov-early-06","level":"early","profession":"publicservice","title":"The 311 escalation","scenario":"You take 311 calls. A resident reports sewage backing up into her basement right now — this needs a crew within the hour, not the standard three-day queue. Your escalation note starts with the caller's full history with the city.","task":"Write an escalation note whose first sentence states the problem and the urgency.","tips":["Lead with what is happening and the response needed.","Address and access details right behind it.","History matters only if it changes the response."],"focus":["impact","clarity"],"placeholder":"Active sewage backup flooding a basement at 118 Oak Crescent — needs a crew within the hour."},
    {"id":"lead-gov-early-07","level":"early","profession":"publicservice","title":"The missing-document voicemail","scenario":"You process building permits. An application is complete except for one thing: the site plan is missing. You're about to leave a voicemail and your habit is to recap the whole application before the point.","task":"Write a 2-3 sentence voicemail script that leads with what's needed.","tips":["First sentence: what we need from you and how to send it.","Then the consequence: on hold until received.","End with your callback number, slowly."],"focus":["clarity","concision"],"placeholder":"Your permit application is on hold for one item: we need the site plan."},
    {"id":"lead-gov-early-08","level":"early","profession":"publicservice","title":"The overnight damage report","scenario":"You're on a municipal works crew. Overnight, a car hit the trench barriers on Birch Road — barriers scattered, trench exposed, no injuries, you've re-secured the site. Your incident report draft opens with when your shift started.","task":"Write the first sentence of the report: what happened, when, and the current state.","tips":["Event, time, and outcome in one sentence.","'Site re-secured, no injuries' is the news your supervisor needs.","Shift logistics belong in the log, not the lead."],"focus":["structure","precision"]},
    {"id":"lead-gov-early-09","level":"early","profession":"publicservice","title":"The shift-swap ask","scenario":"You need to swap your Saturday shift for a family commitment and a colleague has already agreed to take it. Your message to the duty supervisor opens with three sentences of apology and explanation.","task":"Write a 2-sentence request that leads with the ask.","tips":["Sentence one: the swap, the date, who's covering.","Reason in half a sentence — you don't owe a saga.","Make approval a one-word reply."],"focus":["concision","clarity"],"placeholder":"Requesting to swap my Saturday shift with Corporal Diaz, who has agreed to cover —"},
    {"id":"lead-gov-early-10","level":"early","profession":"publicservice","title":"The batch error flag","scenario":"You've discovered that about 30 applications this week were processed under the wrong fee code — each one undercharged by $25. Your email to your supervisor eases in with how you happened to notice.","task":"Write a message that states the error and its scale in the first sentence.","tips":["Lead with what went wrong and how many are affected.","How you found it is one supporting line.","Flag what you've already stopped or checked."],"focus":["clarity","impact"],"placeholder":"About 30 applications this week were processed under the wrong fee code — each undercharged $25."},
    {"id":"lead-gov-early-11","level":"early","profession":"publicservice","title":"The water main call","scenario":"Your crew has found a main break flooding the intersection at Hill and 3rd. You need dispatch to shut the valve upstream and send traffic control. You're tempted to start with how bad the flooding looks.","task":"Write a one-sentence message to dispatch that leads with location and the two actions needed.","tips":["Location, then the two asks, in one sentence.","Vivid description doesn't shut valves — requests do.","Details of the damage can follow once help is moving."],"focus":["clarity","impact"]},
    {"id":"lead-gov-early-12","level":"early","profession":"publicservice","title":"The debrief to the sergeant","scenario":"You attended a noise complaint that resolved without charges — the tenant agreed to shut the party down and the complainant was satisfied. Back at the station, you start recounting the call from the moment you arrived.","task":"Give a 1-2 sentence verbal debrief that leads with the outcome.","tips":["Outcome first: resolved, no charges, both parties satisfied.","Then one line of how, if asked.","Sergeants triage on outcomes."],"focus":["concision","structure"],"placeholder":"The Maple Street noise complaint is resolved — no charges, tenant complied, complainant satisfied."},
    {"id":"lead-gov-early-13","level":"early","profession":"publicservice","title":"The counter-closure decision","scenario":"The registration system has been down for an hour with no ETA. You need your supervisor's call: keep the counter open taking paper forms, or close and post a notice. Your draft message describes the outage history first.","task":"Write a message that puts the decision you need in the first sentence.","tips":["Lead with the choice: paper forms or close?","Give the tradeoff in one line each.","Say what you'll do if you hear nothing by a set time."],"focus":["clarity","structure"],"placeholder":"I need your call: keep the counter open on paper forms, or close until the system is back?"},
    {"id":"lead-gov-early-14","level":"early","profession":"publicservice","title":"The plow down mid-route","scenario":"Your snowplow lost hydraulics halfway through Route 7 during active snowfall. Half the route is uncleared, including the hospital access road. Your radio message to the yard starts with what you think broke.","task":"Write a 1-2 sentence message that leads with the operational impact.","tips":["Lead with what's not getting done: half of Route 7, hospital road included.","Then the ask: replacement unit or reassignment.","Mechanical diagnosis can wait for the yard."],"focus":["impact","clarity"]},
    {"id":"lead-gov-early-15","level":"early","profession":"publicservice","title":"The near-miss report","scenario":"You're a parks worker. A chainsaw kicked back this morning and missed your leg by inches — the guard was worn and you've tagged the saw out of service. Your near-miss report draft opens with a description of the work order.","task":"Write the first two sentences: what nearly happened and what you've done.","tips":["Lead with the near miss, plainly — no softening.","Immediate action taken goes in sentence two.","The point of the report is to prevent the next one; make it land."],"focus":["clarity","impact"],"placeholder":"A chainsaw kickback this morning missed my leg by inches; the blade guard was worn through."},
    {"id":"lead-gov-early-16","level":"early","profession":"publicservice","title":"The filing defect call","scenario":"You're a court clerk. A law office's filing was rejected for a missing signature page, and their deadline is Friday. You're drafting the callback and your instinct is to explain the intake process before the problem.","task":"Write a 2-sentence phone script that leads with the rejection and the fix.","tips":["Sentence one: rejected, why, and the deadline at risk.","Sentence two: exactly how to cure it and by when.","They need to act today — make that unmissable."],"focus":["clarity","precision"]},
    {"id":"lead-gov-early-17","level":"early","profession":"publicservice","title":"The urgent benefits case","scenario":"You're a benefits intake clerk. An applicant's file is stuck in the standard queue, but her utility shutoff is Friday and expedited review exists for exactly this. Your escalation email to the case supervisor opens with the file's full intake history.","task":"Write an escalation that leads with the ask and the deadline.","tips":["First sentence: expedite file #, shutoff is Friday.","One line on why it qualifies.","History only if it affects the decision."],"focus":["clarity","impact"],"placeholder":"Requesting expedited review of file 2214 — the applicant's utility shutoff is Friday and she meets the hardship criteria."},
    {"id":"lead-gov-early-18","level":"early","profession":"publicservice","title":"The live-issue handover","scenario":"You're ending your counter shift. One thing is live: a resident was promised a callback about a disputed parking fine by 15:00 and will escalate if it's missed. Your handover note starts with a calm recap of the day.","task":"Write a handover note that leads with the one thing the next shift must do.","tips":["First line: the promise, the time, the file.","Everything routine goes below the line.","If they read one sentence, it should be this one."],"focus":["structure","clarity"],"placeholder":"One live item: Mr. Okafor (file P-8841) was promised a callback about his parking fine by 15:00 —"},
    {"id":"lead-gov-early-19","level":"early","profession":"publicservice","title":"The overtime ask","scenario":"The passport-renewal backlog hit 60 files today and you can clear a third of it with two hours of overtime tonight. Your message to your supervisor opens with a long description of how the backlog built up.","task":"Write a 2-sentence request that leads with the ask and the payoff.","tips":["Sentence one: two hours OT tonight, clears ~20 files.","Cause of the backlog in one clause, if at all.","A bounded ask with a payoff is easy to approve."],"focus":["concision","impact"]},
    {"id":"lead-gov-early-20","level":"early","profession":"publicservice","title":"The inter-agency delay notice","scenario":"You promised the county health office your inspection notes by today, but a call-out means they'll be ready tomorrow noon. Your draft email spends a paragraph on the staffing situation before mentioning the new date.","task":"Write a 2-sentence notice that leads with the new date.","tips":["New date first — that's what they need to replan around.","Reason in a few words; they don't need the roster.","Offer the partial now if it helps them."],"focus":["clarity","concision"],"placeholder":"My inspection notes will reach you tomorrow by noon, not today as promised."},
    {"id":"lead-gov-early-21","level":"early","profession":"publicservice","title":"The sign nobody reads","scenario":"The office is closing at 15:00 today for a systems upgrade, and you're writing the sign for the door. Your first draft opens with 'Please be advised that due to scheduled essential maintenance...'","task":"Write the first line of the sign — the one fact people need, biggest and first.","tips":["Lead with the fact: closing at 3 PM today.","'Please be advised' delays the news without adding anything.","What to do instead (online, tomorrow's hours) is line two."],"focus":["clarity","audience"],"placeholder":"We close at 3 PM today."},
    {"id":"lead-gov-early-22","level":"early","profession":"publicservice","title":"The system outage ticket","scenario":"The licensing system is down at all four counter stations and the waiting room is filling. Your IT ticket draft starts with your workstation number and browser version, as the form suggests.","task":"Write a ticket description whose first sentence carries the scope and urgency.","tips":["Lead with scope: all four stations, public service stopped.","Technical details follow — they help, but second.","Say how many people are waiting; queues create urgency."],"focus":["impact","precision"]},
    {"id":"lead-gov-early-23","level":"early","profession":"publicservice","title":"The checkpoint SITREP","scenario":"You're reporting the end of a checkpoint shift. One notable event: at 14:20 you turned away a vehicle with no movement documents; the driver complied and departed north. Your draft recounts the shift hour by hour.","task":"Write a 1-2 sentence report that leads with the notable event.","tips":["Notable event first: time, what, outcome.","'Nothing else to report' covers the rest in four words.","The chain of command reads dozens of these — reward the skim."],"focus":["concision","structure"],"placeholder":"At 14:20 we refused passage to a vehicle without movement documents; driver complied and departed north. Nothing else to report."},
    {"id":"lead-gov-early-24","level":"early","profession":"publicservice","title":"The suspected fraud flag","scenario":"The same person has now filed a third assistance application under a slightly different name — you recognize the handwriting and the address. Your note to your supervisor starts with a hedge: 'This may be nothing, but I was going through the files and...'","task":"Write a 2-3 sentence flag that states the concern first, facts after.","tips":["Lead with the concern in plain words: possible duplicate applications.","Then the three facts that raised it — names, dates, address.","State the concern without stating a verdict; that's the supervisor's call."],"focus":["clarity","precision"]},
    {"id":"lead-gov-early-25","level":"early","profession":"publicservice","title":"The answer they actually asked for","scenario":"Your supervisor messages: 'Is the Route 9 pothole patching done?' It is — except one section that needs a full repave and a separate work order. Your draft reply describes the whole week of patching first.","task":"Write a reply that answers the question in the first three words.","tips":["'Done, except...' answers it immediately.","The exception gets one precise sentence.","Don't make a yes/no question cost a paragraph to decode."],"focus":["concision","clarity"],"placeholder":"Done, except one 40-metre section near the bridge that needs a full repave —"}
  ],
  "start-with-the-audience": [
    {"id":"audience-gov-early-01","level":"early","profession":"publicservice","title":"The rejection without the code section","scenario":"A homeowner's deck permit is refused because the setback is 1.2 metres where the zoning bylaw requires 1.5. Your template letter cites 'Section 4.2.3(b) of Bylaw 2019-114' and nothing a homeowner can act on.","task":"Write a 2-3 sentence explanation a homeowner can understand and act on.","tips":["Translate the code into the physical fact: the deck is 30 cm too close to the property line.","Say what they can do next: move it, shrink it, or apply for a variance.","Keep the citation, but as a reference at the end, not the explanation."],"focus":["audience","clarity"],"placeholder":"Your deck as drawn sits 30 cm too close to the property line —"},
    {"id":"audience-gov-early-02","level":"early","profession":"publicservice","title":"The checklist for a nervous applicant","scenario":"An applicant with limited English needs to bring three things to complete her benefits claim: government photo ID, proof of address, and her last two pay stubs. The official checklist calls them 'primary identity document', 'residency verification', and 'income substantiation'.","task":"Rewrite the three items in words anyone can follow.","tips":["Name real objects: your driver's licence or passport, a bill with your address, your last two pay stubs.","One item per line; no item needs a definition.","Test each line: could someone find the object in a drawer from your words alone?"],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-03","level":"early","profession":"publicservice","title":"The road closure from the resident's side","scenario":"Elm Street will be closed between 3rd and 5th for water main replacement, Monday to Thursday. Your draft notice leads with the capital project number and the contractor's name — things no resident cares about.","task":"Write a 3-sentence notice that leads with what residents can and cannot do.","tips":["Lead with their stake: no through traffic, driveway access maintained, parking off-street.","Dates and hours in plain terms: Monday to Thursday, 7 AM to 6 PM.","Project details and contact info come last, small."],"focus":["audience","structure"],"placeholder":"Elm Street will be closed to through traffic Monday to Thursday —"},
    {"id":"audience-gov-early-04","level":"early","profession":"publicservice","title":"Asking a witness for a statement","scenario":"You need a shop assistant who saw a collision to give a written statement. Your opening — 'I require you to provide a witness statement pursuant to our investigation' — makes her visibly anxious.","task":"Rewrite the request in 2-3 sentences of plain language that says why it matters and what it involves.","tips":["Say what it is in her terms: writing down what you saw, in your own words.","Say why it helps: it's how the drivers' insurance and any charges get decided fairly.","Say the cost honestly: about ten minutes, and you can do it here."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-05","level":"early","profession":"publicservice","title":"The online renewal walkthrough","scenario":"An elderly resident wants to renew her pet licence and you're steering her to the website. Your first attempt — 'just log into the portal and navigate to e-services' — got a blank look.","task":"Explain the steps in 3-4 sentences with no system words.","tips":["Start from her screen: what she types, what she'll see, what she clicks.","Replace 'portal' and 'e-services' with what's on the actual page.","Offer the fallback: if it doesn't work, call this number or come back and we'll do it together."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-06","level":"early","profession":"publicservice","title":"The queue system decoded","scenario":"A walk-in is angry that people who arrived after him were served first. The truth is boring: there are separate ticket streams for payments and applications. Your explanation keeps using the words 'streams' and 'service categories'.","task":"Explain in 2 sentences why he saw what he saw, in his terms.","tips":["Start from his observation: yes, they came later — they were in the shorter payments line.","Then his stake: your line is applications, and you're third in it now.","Never make the citizen feel wrong for what they correctly saw."],"focus":["audience","clarity"],"placeholder":"You're right that they came in after you — they were in the payments line, which moves faster."},
    {"id":"audience-gov-early-07","level":"early","profession":"publicservice","title":"The onboarding note without shorthand","scenario":"A new hire starts at your counter Monday. Your draft note is full of house shorthand: 'the batch run', 'back-office days', 'the blue forms', 'escalate to the second floor'. She won't know any of it.","task":"Rewrite one paragraph of counter guidance assuming she knows nothing local.","tips":["Spell out every piece of shorthand the first time you use it.","Explain the why in one clause — the batch run means payments after 4 PM post tomorrow.","Read it back as a stranger: any term you'd have to ask about, define."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-08","level":"early","profession":"publicservice","title":"One outage, two audiences","scenario":"The permit system is down for the afternoon. You owe two messages: a one-line update to your supervisor and a sign for the public counter. Your first draft uses the same sentence for both.","task":"Write both versions — one line each — fitted to each audience.","tips":["Supervisor: scope, impact, and what you're doing (paper intake, IT ticket #).","Public: what they can still do today and what to do instead.","Same fact, different stake — let the stake pick the words."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-09","level":"early","profession":"publicservice","title":"The failed inspection, face to face","scenario":"A restaurant failed its inspection on two points: a walk-in fridge at 8°C (must be 4°C or below) and no soap at the prep-area handwash sink. The owner speaks fast, worried English and asks 'so am I closed?'","task":"Explain the result in 3 sentences: what failed, what it means for today, what fixes it.","tips":["Answer the fear first: no, you are not closed.","Name the two problems as physical things, not violation codes.","Say exactly what re-inspection needs: fridge at 4°C, soap stocked, call this number."],"focus":["audience","clarity"],"placeholder":"You're not closed — but two things must be fixed before I can pass you."},
    {"id":"audience-gov-early-10","level":"early","profession":"publicservice","title":"The boil-water door notice","scenario":"A main break means three streets must boil tap water until further notice. The utility's template opens with 'Precautionary Boil Water Advisory — turbidity exceedance detected'. You're writing the version for door hangers.","task":"Write a 3-sentence notice that leads with the action, in words a tired parent skims at the door.","tips":["Action first: boil tap water for 1 minute before drinking or cooking.","Then who and until when: these streets, until we deliver an all-clear notice.","'Turbidity exceedance' becomes 'the water may not be safe' — the reason, not the measurement."],"focus":["audience","impact"],"placeholder":"Boil your tap water for 1 minute before drinking or cooking."},
    {"id":"audience-gov-early-11","level":"early","profession":"publicservice","title":"The checkpoint explanation","scenario":"You're a soldier on a vehicle checkpoint. A family's car lacks the required movement pass and you must turn them around. The driver doesn't know the system — he just sees an armed stranger blocking his road.","task":"Say in 2-3 plain sentences why you're turning him around and what gets him through next time.","tips":["Lead with his path forward: where to get the pass and what it costs him (an hour, not a day).","Explain the rule from his side — every vehicle, not him specifically.","Calm, specific words lower the temperature more than a raised voice ever will."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-12","level":"early","profession":"publicservice","title":"The held mail at the door","scenario":"You're a postal carrier explaining to a resident why her mail has been held: the porch steps are broken and carriers were told to stop delivering until they're fixed. Your first attempt quoted the 'delivery point hazard suspension' policy.","task":"Explain the hold and the fix in 2 sentences of plain language.","tips":["Her stake first: your mail is safe and waiting; here's how to get it flowing again.","Name the physical cause — the broken second step — not the policy category.","Give the fix and the timeline: fix the step, call this number, delivery resumes next day."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-13","level":"early","profession":"publicservice","title":"The first court date, translated","scenario":"A first-time defendant calls the court counter, scared, asking what happens at his 'first appearance' next week. The accurate answer involves arraignment, disclosure, and adjournment — words that will bounce off him.","task":"Explain what will happen and what he must bring, in 3-4 jargon-free sentences.","tips":["Answer the real fear: it's a short scheduling appearance, not the trial; no one testifies.","Turn each legal term into what he'll experience: the charge is read, you get the paperwork, a next date is set.","End with the concrete: courtroom number, time to arrive, bring photo ID."],"focus":["audience","clarity"],"placeholder":"Next week is a short scheduling appearance, not your trial —"},
    {"id":"audience-gov-early-14","level":"early","profession":"publicservice","title":"The penalty explained to a shop owner","scenario":"A small bakery filed its business licence renewal six weeks late and owes a $150 late fee on top of the renewal. The owner is upset and half-convinced it's a scam. Your draft explanation quotes the fee schedule by section number.","task":"Write a 3-sentence explanation of what the charge is, why it applies, and how to avoid it next year.","tips":["Plain sequence: renewal was due March 31, arrived May 12, late fee applies after 30 days.","Separate the two amounts so the bill stops looking arbitrary.","Give her the next-year fix: renew online in March, or ask for the reminder email."],"focus":["audience","precision"]},
    {"id":"audience-gov-early-15","level":"early","profession":"publicservice","title":"The privacy refusal that stays human","scenario":"A man at the counter asks about his wife's benefits file. You cannot tell him anything — privacy law is absolute here — but 'I can neither confirm nor deny' will read as obstruction to a worried husband.","task":"Refuse in 2-3 sentences that explain the rule from his side and give him a real path.","tips":["Explain the protection points at him too: no one can ask about your file either.","Give the path: she can call us herself, or sign a consent form naming you.","Warm tone, firm line — the rule isn't yours to bend, but the kindness is."],"focus":["audience","clarity"],"placeholder":"I can't discuss anyone's file but your own — the same protection covers your file from anyone who asks."},
    {"id":"audience-gov-early-16","level":"early","profession":"publicservice","title":"The ask IT can act on","scenario":"You want IT to pull how many counter transactions failed after the last system update. Your draft says 'the system has been weird since the update, can you look into it?' — which gives them nothing to query.","task":"Rewrite the request in their terms: which system, what data, what date range.","tips":["Name the system and screen as IT knows them, not as the counter calls them.","Define 'weird' as a measurable: transactions that errored out at payment, June 20 to today.","Say what you'll do with the answer — it helps them pick the right report."],"focus":["audience","precision"]},
    {"id":"audience-gov-early-17","level":"early","profession":"publicservice","title":"The councillor's office wants an answer","scenario":"A city councillor's assistant emails about a constituent whose garbage was missed three weeks running. Your internal notes blame a route restructure and a staffing gap — true, but the assistant needs something they can send the constituent.","task":"Write a 3-sentence reply fit for forwarding: what happened, what's fixed, what the resident should expect.","tips":["Write for the final reader — the constituent — not the assistant.","Own the miss plainly; skip internal causes they can't verify or use.","End with the checkable promise: collection resumes this Thursday; here's the number if it doesn't."],"focus":["audience","impact"]},
    {"id":"audience-gov-early-18","level":"early","profession":"publicservice","title":"'How much longer?' answered honestly","scenario":"An applicant calls weekly about her housing application. It's at stage two of four, roughly two months from a decision. Your stock answer — 'it's in processing' — tells her nothing and guarantees another call.","task":"Write a 2-3 sentence answer that translates the process stage into her terms.","tips":["Give her the map: stage two of four, and what each remaining stage is in one word.","Give the honest range: about two months, and what would speed it up or slow it down.","Tell her what would trigger contact from us, so silence stops meaning 'lost'."],"focus":["audience","precision"],"placeholder":"Your application is at stage two of four — documents verified, now in review."},
    {"id":"audience-gov-early-19","level":"early","profession":"publicservice","title":"The recycling change, resident-first","scenario":"Starting next month, glass moves from the blue bin to depot-only drop-off. The program's draft flyer leads with the contamination-rate statistics that drove the decision.","task":"Write the flyer's first two lines: what changes for the household, then why.","tips":["Lead with the behavior change: glass no longer goes in the blue bin.","Then the one-line why — glass shards ruin the paper bales — because people comply more when told why.","Where and when for the depot goes right after, in plain address form."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-20","level":"early","profession":"publicservice","title":"The bylaw chat in the park","scenario":"You're a bylaw officer approaching four teenagers skateboarding in a plaza where it's prohibited. Opening with 'this is a violation of municipal code' will get you eye-rolls or worse. There's a skate park two blocks away.","task":"Script your 2-sentence opener: the ask, and their alternative, no legalese.","tips":["Lead with the redirect, not the offence: the skate park on Dean Street is two blocks that way.","One plain reason — this plaza's tiles crack and someone bills the city.","Respect gets compliance from teenagers; recitation gets an audience."],"focus":["audience","impact"]},
    {"id":"audience-gov-early-21","level":"early","profession":"publicservice","title":"The rental inspection demystified","scenario":"A first-time landlord calls, worried about his upcoming rental-unit inspection. He imagines white gloves and failure over a scuffed wall. In reality you check smoke alarms, heating, wiring, exits, and damp.","task":"Explain in 3 sentences what is actually checked and what happens if something fails.","tips":["Deflate the fear first: it's a safety check, not a decorating review.","List the five real items in household words.","Explain 'fail' honestly: a list of fixes and a re-visit, not a fine on day one."],"focus":["audience","clarity"]},
    {"id":"audience-gov-early-22","level":"early","profession":"publicservice","title":"Three things, not a lecture","scenario":"You're the constable giving five minutes of home-security advice at a residents' meeting after a string of shed break-ins. Your inherited slide deck has 14 bullet points of crime-prevention theory.","task":"Pick and phrase the three most useful actions for this audience, one sentence each.","tips":["Choose actions this audience can do this weekend, not principles.","Phrase each as a doing: put a motion light over the shed door, not 'consider illumination'.","Three things they remember beat fourteen they forget."],"focus":["audience","concision"],"placeholder":"Three things this weekend: first, a motion light over the shed door —"},
    {"id":"audience-gov-early-23","level":"early","profession":"publicservice","title":"The form-name translation","scenario":"Your office's document checklist tells applicants to bring 'Form RD-7', 'a commissioned statutory declaration', and 'NOA'. You watch people arrive missing items every day because the list names forms, not things.","task":"Rewrite the three items so someone who has never dealt with your office brings the right things.","tips":["Describe the thing and where it comes from: the tax summary the tax agency mails you each spring.","Keep the official name in brackets for staff, after the description.","If an item requires a prior step (getting something witnessed), say so on the same line."],"focus":["audience","precision"]},
    {"id":"audience-gov-early-24","level":"early","profession":"publicservice","title":"The working-level ask across agencies","scenario":"You need the regional transit authority to confirm bus stop relocations before your crew paints new curb markings Thursday. Your draft email is written as if the reader knows your project — they've never heard of it.","task":"Write a 3-4 sentence email that gives a stranger enough context to act, then the precise ask.","tips":["One sentence of orientation: who you are and what's happening on their patch.","The ask with its deadline: confirm the four stop locations by Wednesday noon.","Attach or list the specifics — stop IDs, cross streets — so they can answer without a meeting."],"focus":["audience","structure"]},
    {"id":"audience-gov-early-25","level":"early","profession":"publicservice","title":"The journalist at the counter","scenario":"A local reporter calls your counter asking why permit wait times have doubled. You're not authorized to speak for the department, but a flat 'no comment' becomes its own story. There is a media line that responds same-day.","task":"Script a 2-sentence response that is honest, helpful, and stays in your lane.","tips":["Be human about the limit: counter staff don't speak for the department — that's not evasion, it's accuracy.","Give the real path and make it easy: the media office number, and they do respond same-day.","Never guess at answers on the record; a helpful redirect is the professional move."],"focus":["audience","clarity"],"placeholder":"That's a fair question, and I want you to get an accurate answer rather than my guess —"}
  ],
  "structure-that-carries": [
    {"id":"structure-gov-early-01","level":"early","profession":"publicservice","title":"The incident report skeleton","scenario":"You responded to a shoplifting call: arrived 14:10, suspect gone, statements from the manager and one customer, CCTV secured, file open. Your draft is one long paragraph mixing all of it.","task":"Restructure the report: one summary sentence, then three labelled groups (what happened, evidence gathered, next steps).","tips":["The summary sentence carries the whole event for a skimming reader.","Group by kind, not by the order you did things.","Each group gets a plain label a reviewer can jump to."],"focus":["structure","clarity"],"placeholder":"Summary: Shoplifting at Harmon's Grocery, suspect departed before arrival; statements and CCTV secured, file open."},
    {"id":"structure-gov-early-02","level":"early","profession":"publicservice","title":"Nine events, three buckets","scenario":"Your night-shift log has nine entries: two noise complaints, a fare dispute, three door checks, a lost child (found), a parking obstruction, and a fuel run. The shift report can't just be the list retyped.","task":"Group the nine into 2-3 meaningful buckets and write the one-line summary that sits above them.","tips":["Group by what the reader does with them: needs follow-up, resolved, routine.","The governing line: how the shift went and the one thing that needs attention.","A list is data; grouping is the analysis your sergeant is paying for."],"focus":["structure","concision"]},
    {"id":"structure-gov-early-03","level":"early","profession":"publicservice","title":"SCQA for the growing queue","scenario":"Average wait at your counter has grown from 15 to 40 minutes since a neighbouring office closed. You want your supervisor to request a floating clerk. You have the facts but your draft memo is a heap of them.","task":"Write the memo's first four sentences as SCQA: situation, complication, question, answer.","tips":["Situation: one sentence of stable context the reader already accepts.","Complication: the change that created the problem — the office closure and the 40-minute waits.","Your answer is the recommendation: request the floating clerk; evidence follows below."],"focus":["structure","clarity"],"placeholder":"Our counter has handled walk-in licensing for the east district for five years. Since the Milton office closed in May —"},
    {"id":"structure-gov-early-04","level":"early","profession":"publicservice","title":"PREP at the community meeting","scenario":"At a community meeting a resident asks why Riverside Park is fenced off. You know the answer — storm damage made two big oaks unstable, removal is scheduled, three weeks to reopen — but you tend to ramble when standing.","task":"Give a four-sentence spoken answer using PREP: point, reason, example, point.","tips":["Point: the park is closed for safety and reopens in about three weeks.","Reason and example: the storm left two oaks that could drop limbs on the playground.","Land the same point again in fresh words — that's what they'll repeat to neighbours."],"focus":["structure","audience"]},
    {"id":"structure-gov-early-05","level":"early","profession":"publicservice","title":"One idea, three reasons","scenario":"You want to propose opening the counter 30 minutes earlier. You have seven supporting observations of varying strength. A memo with seven reasons reads like a plea; three strong ones read like a case.","task":"Write the governing recommendation plus your three strongest reasons as labelled bullets.","tips":["One governing sentence: open at 8:30 to cut the 9 AM crush.","Pick the three reasons a skeptic finds hardest to dismiss; drop the rest.","Each bullet: claim first, evidence after the dash."],"focus":["structure","impact"]},
    {"id":"structure-gov-early-06","level":"early","profession":"publicservice","title":"Twelve complaints, three themes","scenario":"This month's complaint file has twelve entries about the transit interchange: litter, a broken bench, aggressive panhandling, poor lighting, two slip hazards, and assorted others. Your monthly summary currently retypes all twelve.","task":"Sort the twelve into themes and write one sentence per theme for the summary.","tips":["Themes should suggest owners: maintenance items, safety items, enforcement items.","Each theme sentence: the pattern, the count, the worst instance.","The reader should know where to send each theme without reading the raw list."],"focus":["structure","concision"],"placeholder":"Three themes this month: maintenance (5 complaints, worst: the broken bench), safety —"},
    {"id":"structure-gov-early-07","level":"early","profession":"publicservice","title":"The case note that carries its decision","scenario":"Your benefits case notes read like diaries: everything the applicant said, in order. Six months later nobody — including you — can find the decision or why it was made.","task":"Write a case-note template of 3-4 lines: decision, key evidence, next step, date.","tips":["Decision first — it's what every future reader is hunting for.","Evidence: only what the decision rests on, not the whole conversation.","Next step with a date turns a note into a plan."],"focus":["structure","precision"]},
    {"id":"structure-gov-early-08","level":"early","profession":"publicservice","title":"The handover binder page","scenario":"You're building the handover page for your counter role before rotating out. Your notes are forty scattered lines: passwords locations, weekly rhythms, who fixes what, three unfinished cases.","task":"Design the page's structure: 3-4 sections in the order a stranger needs them, one line saying what goes in each.","tips":["Order by urgency of need: live items first, weekly rhythms second, reference last.","Sections named by the reader's question: 'What's in flight?', 'Who do I call?'","If a stranger can run day one from the page, the structure works."],"focus":["structure","audience"]},
    {"id":"structure-gov-early-09","level":"early","profession":"publicservice","title":"The second printer, pyramid-style","scenario":"The single ticket printer jams daily and the queue dissolves into arguments each time. You want a second printer (about $400). Your draft request describes three weeks of jams in chronological order.","task":"Rewrite as a pyramid: the ask on top, then 2-3 grouped supporting points.","tips":["Top line: request one additional ticket printer, ~$400, for counter 1.","Group support by type: frequency of failure, cost of failure, cheapness of fix.","Chronology is how you lived it; grouping is how they'll approve it."],"focus":["structure","impact"],"placeholder":"Request: a second ticket printer for the main counter (~$400)."},
    {"id":"structure-gov-early-10","level":"early","profession":"publicservice","title":"The statement that leads with the crash","scenario":"You're helping a witness structure her statement about a collision. Her retelling starts at breakfast. Statements must be accurate and chronological — but the key fact shouldn't arrive in paragraph four.","task":"Write the statement's opening: one sentence naming the key event, then the chronology begins.","tips":["Open with the anchor: 'I witnessed a collision between a red van and a cyclist at Main and 3rd at about 8:40.'","Then run the chronology from a sensible start — not breakfast.","The anchor sentence lets every later detail attach to something."],"focus":["structure","precision"]},
    {"id":"structure-gov-early-11","level":"early","profession":"publicservice","title":"Signposting the muster briefing","scenario":"You have three items for this morning's roll call: a new radio channel assignment, a stolen blue van to watch for, and a reminder about court attendance Friday. Delivered as a stream, the room retains one of three.","task":"Script the briefing opener and transitions: announce three items, number them as you go.","tips":["Open with the count: 'Three items this morning.'","Number each transition: 'Second —'. The numbering is the structure, spoken aloud.","Close by repeating the one that matters most today."],"focus":["structure","clarity"],"placeholder":"Three items this morning. First: radio channels change today —"},
    {"id":"structure-gov-early-12","level":"early","profession":"publicservice","title":"Critical, minor, advisory","scenario":"Your housing inspection found nine issues, from a blocked fire exit to a dripping tap. Your draft lists them in the order you walked the building — so the blocked exit sits at item six.","task":"Restructure the findings into three severity groups and write the one-line summary above them.","tips":["Severity is the reader's sorting need — landlord and file reviewer both act by it.","Summary line: counts per group and the single most urgent item.","Within each group, order by cost or effort to fix — help them plan."],"focus":["structure","impact"]},
    {"id":"structure-gov-early-13","level":"early","profession":"publicservice","title":"SCQA for the pothole backlog","scenario":"Pothole work orders are closed on a 12-day average, up from 5, because crews drive cross-town between jobs. Batching by neighbourhood would fix it. You want to pitch this to the works supervisor in one tight paragraph.","task":"Write the paragraph as SCQA in four sentences.","tips":["Situation: how orders are dispatched today, neutrally.","Complication: the number that changed — 5 days to 12.","Answer: batch by neighbourhood — and one sentence of what that looks like Monday."],"focus":["structure","clarity"]},
    {"id":"structure-gov-early-14","level":"early","profession":"publicservice","title":"The two-minute stand-up update","scenario":"At the weekly team meeting you get two minutes. You have a mess of material: four files closed, one stuck case, a training you attended, and a request for help with a spreadsheet. Last week you ran over and got cut off.","task":"Structure the two minutes: pick an order and write your opening sentence.","tips":["Order by what the room must act on: the stuck case and the help request outrank the closed files.","Open with the shape: 'One blocker, one ask, and quick status.'","Time spent structuring is time the meeting doesn't spend decoding you."],"focus":["structure","concision"],"placeholder":"One blocker, one ask, then quick status."},
    {"id":"structure-gov-early-15","level":"early","profession":"publicservice","title":"The yard's broken kit, grouped","scenario":"The works yard whiteboard lists eleven broken or missing items — a chainsaw, two radios, a tamper, gloves, cones, and more. You're turning it into a maintenance-and-purchase request and the raw list won't survive contact with a budget holder.","task":"Group the items into 2-3 categories with a header line stating totals and the most urgent item.","tips":["Group by decision type: repair vs replace vs restock consumables.","The header does the math for them: 11 items, roughly $2,300, one safety-critical.","Flag the safety-critical item so it can't be deferred with the gloves."],"focus":["structure","precision"]},
    {"id":"structure-gov-early-16","level":"early","profession":"publicservice","title":"Mirror their four questions","scenario":"The regional office emailed four numbered questions about your counter's intake stats. Your draft reply is one flowing paragraph that answers them out of order and skips number three.","task":"Restructure the reply: mirror their numbering, one answer per number, shortest first line each.","tips":["Answer in their structure, not yours — they'll check off each number.","Lead each answer with the verdict, then the caveat.","If you can't answer one, say so under its number with a date you will."],"focus":["structure","clarity"]},
    {"id":"structure-gov-early-17","level":"early","profession":"publicservice","title":"Lost property in five steps","scenario":"The lost-property procedure lives in a dense policy paragraph. You explain it aloud a dozen times a day, differently each time, and callers still get it wrong.","task":"Turn the paragraph into a numbered 4-5 step script you can say the same way every time.","tips":["One action per step, in the order the caller does them.","Start each step with the verb: bring, fill in, wait, collect.","A stable script frees your attention for the person, not the procedure."],"focus":["structure","clarity"]},
    {"id":"structure-gov-early-18","level":"early","profession":"publicservice","title":"The patrol report frame","scenario":"You're a soldier writing up a routine patrol that had one deviation: a washed-out track forced a detour and cost an hour. Your draft is a wall of narrative from departure to return.","task":"Restructure into four labelled parts: task, execution, deviations, recommendation — one or two sentences each.","tips":["Task: the mission in one line, as assigned.","Deviations get their own section — that's what the chain actually scans for.","Recommendation: mark the track impassable on the route overlay; make it actionable."],"focus":["structure","concision"],"placeholder":"Task: routine mounted patrol, checkpoints 1-4, 08:00-12:00."},
    {"id":"structure-gov-early-19","level":"early","profession":"publicservice","title":"One message, then the FAQ","scenario":"A new $30 processing fee starts next month and you're writing the counter FAQ. Your draft answers eight questions but never states the one governing message they all hang off.","task":"Write the governing message (one sentence), then pick the three questions that must follow it.","tips":["Governing line: what changes, when, and for whom — everything else is detail.","Choose the three questions people will actually ask: why, who's exempt, what if I applied already.","Every answer should visibly connect back to the governing line."],"focus":["structure","audience"]},
    {"id":"structure-gov-early-20","level":"early","profession":"publicservice","title":"The voicemail into a work order","scenario":"A resident's rambling two-minute voicemail mentions a leaning tree, a previous complaint, her neighbour's opinion, and — buried in the middle — that a large branch is hanging over a public sidewalk. You're creating the service request.","task":"Write the structured request: issue, location, risk, requested action — one line each.","tips":["Extract only what a crew needs; the neighbour's opinion isn't a field.","The hanging branch over the sidewalk is the issue; the leaning tree is context.","If the caller's words were vague on location, flag exactly what needs confirming."],"focus":["structure","precision"]},
    {"id":"structure-gov-early-21","level":"early","profession":"publicservice","title":"PREP for the fee-waiver question","scenario":"Several times a week someone at your counter asks: 'Can't you just waive the fee?' You improvise every time, and it comes out apologetic and shapeless.","task":"Script a four-sentence PREP answer: point, reason, example, point.","tips":["Point: counter staff can't waive fees — but there is a formal waiver process.","Example makes it real: last month two hardship waivers were granted through the form.","Restating the point sends them to the process, not to arguing with you."],"focus":["structure","clarity"],"placeholder":"I can't waive fees at the counter — but there's a formal waiver you can apply for, and it does get granted."},
    {"id":"structure-gov-early-22","level":"early","profession":"publicservice","title":"Worked, didn't, change","scenario":"You attended the new de-escalation training and your supervisor wants feedback the training office can use. Your draft is a paragraph of impressions with no shape.","task":"Restructure into three labelled lines: what worked, what didn't, one change to make.","tips":["The three labels do the organizing — fill each with a specific, not a mood.","'The role-plays' beats 'the interactive parts'; name the exact exercise.","One recommended change is worth five observations."],"focus":["structure","concision"]},
    {"id":"structure-gov-early-23","level":"early","profession":"publicservice","title":"Who does what, when","scenario":"Saturday's festival needs parks (barriers by 07:00), police (road closure at 08:00), and your bylaw team (vendor checks from 09:00). Your coordination email describes the day as a story, and last year two agencies showed up out of order.","task":"Restructure the email as a timeline table in text: time — agency — action, one line per row.","tips":["One row per commitment; a story hides commitments, a table exposes them.","Put each agency's name at the start of its rows so they can scan for themselves.","End with the single confirm-back ask: reply confirming your rows by Thursday."],"focus":["structure","clarity"]},
    {"id":"structure-gov-early-24","level":"early","profession":"publicservice","title":"The confusing form, evidenced","scenario":"Question 7 on the intake form confuses applicants — you spend hours a week re-explaining it and roughly a third of forms come back wrong at that question. You're writing to the forms team, who have never met an applicant.","task":"Structure the memo: the problem in one line, then evidence grouped under 2-3 headers, then the suggested rewording.","tips":["Lead with the cost: staff hours and error rate, not your frustration.","Group evidence so it argues: error data, counter observations, the specific misreadings.","Ending with a concrete suggested rewording turns a complaint into a proposal."],"focus":["structure","impact"]},
    {"id":"structure-gov-early-25","level":"early","profession":"publicservice","title":"A year in three themes","scenario":"Your annual self-assessment draft lists twenty tasks you completed. It reads like a timesheet, and your supervisor will skim it in ninety seconds before your review.","task":"Restructure around three themes of growth or contribution, with the two best examples under each.","tips":["Themes are claims: 'became the counter's problem-solver for complex files'.","Tasks demote to evidence — pick the two strongest per theme, cut the rest.","Ninety seconds should leave the reader with three sentences about you, not twenty."],"focus":["structure","impact"],"placeholder":"Theme one: I became the front counter's go-to for complex applications."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-gov-early-01","level":"early","profession":"publicservice","title":"'It has come to our attention'","scenario":"Your office's standard letter opens: 'It has come to our attention that the documentation submitted in support of your application may be incomplete in certain respects.' Fifteen words to say 'your application is missing something' — and it doesn't even say what.","task":"Rewrite the opening in under ten words, naming the missing item.","tips":["'It has come to our attention' adds zero information — cut the phrase entirely.","'May be incomplete in certain respects' hides the fact; name the missing document.","Every word should either inform or direct."],"focus":["concision","clarity"],"placeholder":"Your application is missing one document: proof of address."},
    {"id":"concise-gov-early-02","level":"early","profession":"publicservice","title":"The hedge-free request","scenario":"Your draft to the sergeant reads: 'I was just wondering if it might possibly be feasible, when convenient, to perhaps look at rotating the radar duty, if that makes sense.' You do want radar duty rotated.","task":"Rewrite as one direct sentence.","tips":["Count the hedges: wondering, might, possibly, perhaps, if that makes sense — all can go.","'Request' or 'I'd like' carries the same politeness with none of the fog.","Respect lives in tone, not in padding."],"focus":["concision","clarity"]},
    {"id":"concise-gov-early-03","level":"early","profession":"publicservice","title":"Nominalizations in the notice","scenario":"The draft notice reads: 'The implementation of the closure of the east parking area will take effect for the duration of the resurfacing operation.' Three nominalizations deep, the reader still doesn't know when they can't park.","task":"Rewrite with verbs doing the work, in one sentence with dates.","tips":["'Implementation of the closure' → 'we are closing'; let verbs act.","Add what the noun-pile omitted: the actual dates.","If a sentence has three '-tion' words, it's hiding at least one actor."],"focus":["concision","clarity"],"placeholder":"The east parking area closes Monday to Friday next week while we resurface it."},
    {"id":"concise-gov-early-04","level":"early","profession":"publicservice","title":"The report paragraph, halved","scenario":"Your incident paragraph runs six sentences: 'Upon arrival at the location, I proceeded to make contact with the complainant, who indicated to me that...' — police-report stuffing that doubles the length without adding a fact.","task":"Rewrite the paragraph at half its length with every fact intact.","tips":["'Proceeded to make contact with' is 'spoke to'.","'Indicated to me that' is 'said'.","Halving isn't summarizing — every fact stays; only the padding goes."],"focus":["concision","precision"]},
    {"id":"concise-gov-early-05","level":"early","profession":"publicservice","title":"'I am writing to inform you'","scenario":"Your email starts: 'I am writing to inform you that I wanted to bring to your attention an issue regarding the situation with the mail sorting machine.' The machine is jammed and needs a technician.","task":"Rewrite the opening so the first sentence is the news.","tips":["'I am writing to inform you' — they know; they're reading it.","'An issue regarding the situation with' is one word: the sorter is jammed.","Meta-commentary about the message delays the message."],"focus":["concision","clarity"],"placeholder":"The mail sorter is jammed and needs a technician."},
    {"id":"concise-gov-early-06","level":"early","profession":"publicservice","title":"Each and every redundant pair","scenario":"The bylaw reminder letter says residents must 'cease and desist', act 'promptly and without delay', and keep bins 'fully and completely' off the sidewalk 'at all times whatsoever'. It reads like a costume, not a letter.","task":"Rewrite the sentence keeping one word from each pair.","tips":["Doubled words don't double the authority — pick the stronger of each pair.","'At all times whatsoever' is 'always' — or often nothing.","Plain words carry more force because people finish reading them."],"focus":["concision","clarity"]},
    {"id":"concise-gov-early-07","level":"early","profession":"publicservice","title":"The 200-word sign","scenario":"The notice taped to your counter runs 200 words explaining the new appointment system, its rationale, its history, and its exceptions. Nobody has ever finished it. People still walk up without appointments.","task":"Cut it to 30 words or fewer that change behavior.","tips":["A sign is read in three seconds — write for the walk-past.","Behavior first: book before you come, at this address or number.","Rationale and history go on the website, not the door."],"focus":["concision","audience"],"placeholder":"Appointments required. Book at city.gov/appointments or call 555-0140. Walk-ins: Wednesdays only, 9-12."},
    {"id":"concise-gov-early-08","level":"early","profession":"publicservice","title":"The 20-second voicemail","scenario":"Your callback voicemails average ninety seconds: greeting, recap of the whole file, the point, a second recap, three sign-offs. Residents call back confused about what you actually need.","task":"Script a voicemail of 20 seconds: who, what you need, how to reach you.","tips":["One breath of identity: name, office, about your application.","One sentence of ask, one repeat of the number — slowly.","If it doesn't fit in 20 seconds, it's two calls or a letter."],"focus":["concision","clarity"]},
    {"id":"concise-gov-early-09","level":"early","profession":"publicservice","title":"Radio brevity","scenario":"Your radio update ran four sentences: how the traffic stop began, what the driver said, your impressions, and — finally — that you need a registration check. Dispatch had to ask you to repeat the plate.","task":"Rewrite as one transmission: the request, the plate, your location.","tips":["Radio time is shared — every extra second blocks the channel.","Request first, then the data dispatch needs to fulfil it.","Impressions go in the report, not on the air."],"focus":["concision","precision"],"placeholder":"Requesting registration check, plate Bravo-Kilo-Tango 4-4-2, Main at 7th."},
    {"id":"concise-gov-early-10","level":"early","profession":"publicservice","title":"The apology spiral","scenario":"Your delay email apologizes four times in five sentences: 'so sorry', 'apologies again for', 'I really regret', 'sorry once more'. The new date appears nowhere.","task":"Rewrite with one apology, the new date, and one line on prevention.","tips":["One sincere apology outweighs four reflexive ones.","The reader forgives faster when they get the new date and a reason to believe it.","Grovel time is better spent on the fix."],"focus":["concision","impact"]},
    {"id":"concise-gov-early-11","level":"early","profession":"publicservice","title":"'It was determined that'","scenario":"The decision letter reads: 'Following a review of the materials provided, it was determined that the application could not be approved at this time.' Who determined? Why not? The passive fog protects nobody and informs nobody.","task":"Rewrite in active voice, naming the reason, in one or two sentences.","tips":["Passive voice here isn't neutral — it's evasive; say 'we reviewed and refused because...'.","'At this time' implies reapplying might work; say whether that's true.","Active voice forces you to include the fact the reader needs most: the reason."],"focus":["concision","clarity"],"placeholder":"We reviewed your application and refused it because the property sits in a flood zone."},
    {"id":"concise-gov-early-12","level":"early","profession":"publicservice","title":"Case-note filler","scenario":"Your case notes are stuffed with 'as per our conversation', 'in regards to the aforementioned', 'at this point in time', and 'for all intents and purposes'. A colleague covering your files calls them 'archaeology'.","task":"Rewrite a three-line case note with all filler phrases removed.","tips":["'As per our conversation' → 'we discussed'; 'at this point in time' → 'now' or nothing.","'Aforementioned' means you should restructure so the reference is obvious.","Notes exist for the next reader — write at their reading speed."],"focus":["concision","clarity"]},
    {"id":"concise-gov-early-13","level":"early","profession":"publicservice","title":"The handover email, halved","scenario":"Your end-of-shift handover email runs 300 words for a shift where two things matter: a promised callback and a printer that needs paper before 9 AM. The rest is narration of routine.","task":"Cut the email to under 80 words without losing either action item.","tips":["Start from the two actions; add back only what they need to be done right.","'It was a fairly typical shift' — the reader learns nothing; cut.","Routine is the default; only report the exceptions."],"focus":["concision","structure"]},
    {"id":"concise-gov-early-14","level":"early","profession":"publicservice","title":"The throat-clearing memo","scenario":"Your memo to the district office opens with two sentences of throat-clearing: 'I hope this finds you well. I wanted to take a moment to reach out regarding a matter that has recently arisen.' The matter is a broken streetlight cluster.","task":"Delete the wind-up and write a first sentence that carries the matter.","tips":["Warmth is fine in a greeting line; it shouldn't cost the reader two sentences of nothing.","'A matter that has recently arisen' — name it: six streetlights out on Carter Road.","The first sentence should survive being the only sentence read."],"focus":["concision","clarity"],"placeholder":"Six streetlights are out on Carter Road between the school and the rail bridge."},
    {"id":"concise-gov-early-15","level":"early","profession":"publicservice","title":"Ten lines into three steps","scenario":"The internal procedure for processing a refund runs ten prose lines. New staff keep a printed copy and still miss steps. Only three actions actually matter: verify the receipt, complete form R-2, route to finance.","task":"Rewrite the procedure as a checklist of three verb-first steps.","tips":["Prose hides steps; checklists expose them.","Start each step with its verb and end with its 'done' condition.","If a line isn't an action, it's a note — move it below the checklist."],"focus":["concision","structure"]},
    {"id":"concise-gov-early-16","level":"early","profession":"publicservice","title":"The backstory-heavy IT ticket","scenario":"Your IT ticket about a broken barcode scanner includes the scanner's purchase year, two previous unrelated faults, your theory about dust, and — in the last line — that it stopped scanning today.","task":"Rewrite the ticket in three lines: what's broken, since when, what you need.","tips":["IT triages on symptom and impact, not on history.","The theory about dust is fine — as one optional line at the end, labelled as a guess.","Three tight lines get faster service than three paragraphs."],"focus":["concision","precision"]},
    {"id":"concise-gov-early-17","level":"early","profession":"publicservice","title":"The SITREP with fat trimmed","scenario":"Your situation report runs twelve lines; the receiving HQ logs three facts from it: position unchanged, one vehicle down awaiting part, supplies green. The other nine lines are weather poetry and repetition.","task":"Rewrite the SITREP in four lines or fewer.","tips":["Report by exception: unchanged things get one word, not one paragraph.","Each line one topic: position, equipment, supplies, personnel.","The reader is logging your report into a table — write in table-ready lines."],"focus":["concision","precision"],"placeholder":"Position unchanged. One vehicle down — awaiting alternator, ETA tomorrow. Supplies green. Personnel green."},
    {"id":"concise-gov-early-18","level":"early","profession":"publicservice","title":"'At this point in time'","scenario":"Your status update contains 'at this point in time' twice, 'in the near future' once, and 'due to the fact that' three times — 21 words that could be seven: now, soon, because.","task":"Rewrite the update replacing every stock phrase with its short form.","tips":["'At this point in time' = now; 'due to the fact that' = because.","Stock phrases are habits, not choices — hunt them mechanically.","Read the result aloud; short forms sound more confident, not less formal."],"focus":["concision","clarity"]},
    {"id":"concise-gov-early-19","level":"early","profession":"publicservice","title":"The meeting notice that fits a fridge","scenario":"The public meeting notice runs 180 words. Residents need five facts: topic, date, time, place, and how to comment if they can't attend. Everything else is boilerplate the law doesn't even require.","task":"Rewrite the notice in five lines, one fact per line.","tips":["Format is the cut: five labelled lines beat a paragraph.","Topic in resident terms: 'proposed dog park at Keller Field', not the file number.","The 'can't attend?' line captures everyone the meeting time excludes."],"focus":["concision","audience"]},
    {"id":"concise-gov-early-20","level":"early","profession":"publicservice","title":"The double-explained rule","scenario":"Your eligibility letter explains the residency requirement in paragraph two, then explains it again in different words in paragraph four. Applicants quote the two versions against each other at your counter.","task":"Merge the two explanations into one authoritative sentence.","tips":["Two phrasings of one rule create two rules in the reader's mind.","Keep the version with the concrete test: 12 months at an address in the city.","Say it once, clearly, and reference it thereafter."],"focus":["concision","precision"]},
    {"id":"concise-gov-early-21","level":"early","profession":"publicservice","title":"The callback note on one card","scenario":"Your colleague takes over your callbacks tomorrow. Your note about Mrs. Reyes runs a full page. What matters: she's owed a decision on file H-2280, promised by Thursday, prefers calls after 2 PM, and is anxious about her hearing date.","task":"Cut the note to four lines that fit an index card.","tips":["The card test forces the ranking a page never does.","Each line: one fact your colleague acts on.","If it doesn't change what the colleague says or does, it's off the card."],"focus":["concision","audience"]},
    {"id":"concise-gov-early-22","level":"early","profession":"publicservice","title":"Two minutes into thirty seconds","scenario":"Your muster update on the vandalism pattern takes two minutes because you narrate every incident. The pattern is simple: six broken windows, all within two blocks of the skate park, all between 10 PM and midnight, Fridays.","task":"Script a 30-second version that gives only the pattern and the ask.","tips":["The pattern IS the briefing; the incidents are the appendix.","One ask at the end: extra pass on Fridays, 10 to 12.","Details available on request — say that, and stop."],"focus":["concision","impact"],"placeholder":"Six broken windows in three weeks, all within two blocks of the skate park, all Friday nights between 10 and midnight."},
    {"id":"concise-gov-early-23","level":"early","profession":"publicservice","title":"The hedged safety concern","scenario":"Your safety report reads: 'I might be wrong, but it seems like the loading dock ramp is maybe getting a bit slippery when it rains, which could possibly be a concern.' Someone will fall on that ramp while this sentence apologizes for existing.","task":"Rewrite as one direct sentence of hazard and one of action.","tips":["Hedging a hazard transfers your discomfort onto someone's ankle.","State what you observed: the ramp is slippery when wet; two near-slips this month.","You're not claiming certainty — you're claiming it needs checking. Say that plainly."],"focus":["concision","impact"],"placeholder":"The loading dock ramp is slippery when wet — two near-slips this month. It needs anti-slip tread."},
    {"id":"concise-gov-early-24","level":"early","profession":"publicservice","title":"The service-page blurb, halved","scenario":"The web page describing your counter's services runs 160 words of committee-written prose. Analytics show visitors leave in nine seconds. The page needs to answer: what can I do here, when, and what do I bring.","task":"Rewrite the blurb at half the length, answering the three visitor questions first.","tips":["Nine seconds is the budget — front-load the three answers.","Cut every sentence about the department; keep every sentence about the visitor.","Bulleted 'bring:' beats a paragraph containing the same list."],"focus":["concision","audience"]},
    {"id":"concise-gov-early-25","level":"early","profession":"publicservice","title":"CYA padding vs the facts","scenario":"Your escalation email about a missed inspection deadline is padded with self-protection: 'as I mentioned previously', 'through no fault of my own', 'as per protocol I did attempt'. The padding buries the two facts that matter: the deadline passed Tuesday, and the file needs reassignment.","task":"Rewrite the escalation in three sentences: fact, fact, ask — keeping one brief line of relevant context.","tips":["A clean factual record protects you better than defensive phrasing.","'I flagged this on the 12th' is a fact and belongs; 'through no fault of my own' is a plea and doesn't.","End on the ask, not on the defense."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-gov-early-01","level":"early","profession":"publicservice","title":"'Intoxicated' is a conclusion","scenario":"Your arrest notes say the male was 'clearly intoxicated'. In court, that word is your opinion — what stands up is what you observed: a strong smell of alcohol on his breath, slurred speech, and swaying that forced him to hold the wall.","task":"Rewrite the sentence as the three observations, not the conclusion.","tips":["Write what your senses recorded; let the reader draw the conclusion.","'Smell of alcohol on breath, slurred speech, unsteady on feet' survives cross-examination — 'intoxicated' invites it.","Keep the observations in the order you made them."],"focus":["precision","clarity"],"placeholder":"I noted a strong smell of alcohol on his breath, slurred speech, and that he held the wall to stay upright."},
    {"id":"precision-gov-early-02","level":"early","profession":"publicservice","title":"A description units can act on","scenario":"You're broadcasting a suspect description after a purse snatch: your first attempt is 'male, average height, dark clothing, ran off'. Three units are listening and none of them can use a word of it.","task":"Say a one-sentence description with height range, build, one distinctive item, and direction of travel.","tips":["'Average' describes no one — give a range: 175 to 185 cm.","One distinctive item beats five generic ones: the red ball cap, the limp.","Direction of travel is the most actionable word in the sentence — never drop it."],"focus":["precision","impact"],"placeholder":"Male, 175 to 185, heavy build, grey hoodie with a red ball cap, last seen running north on Culver toward the rail bridge."},
    {"id":"precision-gov-early-03","level":"early","profession":"publicservice","title":"'Several complaints' becomes a count","scenario":"Your email asking the sergeant for extra patrols says there have been 'several complaints' about the Elm Street corner. You have the CAD numbers in front of you: 11 calls in 14 days, seven of them between 22:00 and midnight.","task":"Rewrite the sentence with the count, the period, and the pattern.","tips":["'Several' costs you credibility; 11-in-14-days earns the patrol.","The time clustering is the actionable part — it tells them when to be there.","Cite where the numbers come from so they're checkable."],"focus":["precision","impact"],"placeholder":"CAD shows 11 calls to the Elm and 4th corner in the last 14 days, seven of them between 22:00 and midnight."},
    {"id":"precision-gov-early-04","level":"early","profession":"publicservice","title":"The size-up that travels","scenario":"You're first engine on scene and your radio size-up is 'we've got a decent fire going here'. Incoming units and the chief are building their whole response off your words — and 'decent' builds nothing.","task":"Say a one-sentence size-up: building type, what's showing, from where.","tips":["The standard skeleton: what building, what's showing, which side.","'Smoke from two second-floor windows, side A' lets everyone behind you plan.","Adjectives burn airtime; nouns and numbers direct trucks."],"focus":["precision","clarity"],"placeholder":"Two-storey detached, heavy smoke from two second-floor windows on side A, nothing through the roof."},
    {"id":"precision-gov-early-05","level":"early","profession":"publicservice","title":"'Aggressive' is a verdict","scenario":"Your patient care report says the man 'became aggressive'. If this ends up reviewed — or in court — that word is your judgment. What happened: he raised his voice, clenched his fists, stepped toward your partner, and refused to sit on the stretcher.","task":"Rewrite the line as the four observed actions.","tips":["Behaviors are evidence; labels are argument.","List actions in sequence — escalation order matters to reviewers.","If you took a step in response (moved back, called for police), record it in the same breath."],"focus":["precision","clarity"],"placeholder":"The patient raised his voice, clenched both fists, stepped toward my partner, and refused to sit on the stretcher."},
    {"id":"precision-gov-early-06","level":"early","profession":"publicservice","title":"The pothole with dimensions","scenario":"Your works-crew report flags a 'large pothole' on Route 4. The dispatcher who reads it can't tell a nuisance from an axle-breaker, so it gets the standard queue. You measured it: 60 cm across, 12 cm deep, square in the westbound wheel track.","task":"Rewrite the flag with the measurements and why they matter.","tips":["Dimensions turn a complaint into a priority calculation.","Location within the lane is the danger detail — wheel track beats shoulder.","One line of consequence: at 80 km/h this one bends rims."],"focus":["precision","impact"],"placeholder":"Pothole westbound Route 4 at the 7 km marker: 60 cm across, 12 cm deep, centred in the wheel track."},
    {"id":"precision-gov-early-07","level":"early","profession":"publicservice","title":"'A while' has a number","scenario":"A counter applicant asks how long her licence renewal will take. Your stock answer — 'a while, we're backed up' — guarantees a follow-up call. The truth is knowable: currently 15 business days against the usual 10.","task":"Give a 1-2 sentence answer with the current number and what would change it.","tips":["A number she can plan around ends the conversation; 'a while' extends it.","Give the honest current figure, not the brochure figure.","Tell her what arrival of X would speed it up, if anything can."],"focus":["precision","audience"],"placeholder":"Right now renewals are taking about 15 business days — five more than usual."},
    {"id":"precision-gov-early-08","level":"early","profession":"publicservice","title":"Evidence for 'the form confuses people'","scenario":"You tell your supervisor the redesigned intake form is 'confusing people'. She shrugs — impressions are cheap. Your tally from yesterday isn't: 14 of 30 submitted forms had the same field wrong, the income box that now sits under the wrong heading.","task":"Rewrite the claim anchored in the count and the specific field.","tips":["A claim a skeptic can check is a claim that gets acted on.","14 of 30, same field, one day — three specifics that end the debate.","Name the fix you suspect so the evidence points somewhere."],"focus":["precision","impact"],"placeholder":"Yesterday 14 of 30 forms came back with the same error: the income field, which now sits under the wrong heading."},
    {"id":"precision-gov-early-09","level":"early","profession":"publicservice","title":"'Shortly after' vs the CAD clock","scenario":"Your incident report reads 'shortly after arriving I noticed the rear door was open'. The CAD log has real times: on scene 21:14, rear door observed and called in at 21:16. Vague time words in a report invite a defence lawyer to fill the gap for you.","task":"Rewrite the sentence with the logged times.","tips":["Every 'shortly', 'later', and 'a few minutes' should become a clock time if one exists.","Cite the source of the time — CAD, your notebook, the radio log.","Precision about time is precision about your credibility."],"focus":["precision","structure"],"placeholder":"I arrived on scene at 21:14; at 21:16 I observed the rear door standing open and reported it to dispatch."},
    {"id":"precision-gov-early-10","level":"early","profession":"publicservice","title":"The fuel state, with its math","scenario":"You're a private reporting the section's fuel state before a field exercise. Your draft says there 'should be enough'. The numbers you actually have: 340 litres on hand, burn rate about 60 litres a day at current tempo — call it five and a half days.","task":"Write a one-sentence report giving the quantity, the rate, and the days remaining.","tips":["'Should be enough' transfers your uncertainty to your commander.","Quantity, consumption rate, days remaining — the three numbers every supply report needs.","State the assumption behind the rate so the estimate can be challenged fairly."],"focus":["precision","clarity"],"placeholder":"Fuel state: 340 litres on hand, burning roughly 60 per day — five and a half days at current tempo."},
    {"id":"precision-gov-early-11","level":"early","profession":"publicservice","title":"'Acting suspicious' unpacked","scenario":"Your notes for a stop say the man was 'acting suspicious'. What you actually observed: he walked past the same closed shop three times in ten minutes, tried the door handle twice, and looked up and down the street before each try.","task":"Rewrite the note as the specific observed behaviors with times.","tips":["'Suspicious' is the inference the court draws — your job is the observations that justify it.","Count the repetitions: three passes, two handle tries.","What the camera would have seen is the standard for what goes in the notes."],"focus":["precision","clarity"],"placeholder":"Between 23:05 and 23:15 the male passed the closed shopfront three times, tried the door handle twice, and scanned the street before each attempt."},
    {"id":"precision-gov-early-12","level":"early","profession":"publicservice","title":"'Damaged' vs the damage","scenario":"Your vehicle report says the mail van was 'damaged in the incident'. Fleet needs to decide today whether it drives or gets towed, and 'damaged' answers nothing. The facts: 30 cm dent in the driver door, door won't latch, mirror gone, engine and lights fine.","task":"Rewrite the line so fleet can make the tow-or-drive call from your words alone.","tips":["Describe damage by part and function: what's bent, and what no longer works.","End with the operational answer: drivable or not, in your assessment.","'Fine' is worth stating too — what still works narrows the decision."],"focus":["precision","concision"],"placeholder":"Driver door has a 30 cm dent and won't latch; mirror sheared off; engine, brakes, and lights unaffected. Not safe to drive with the door unsecured."},
    {"id":"precision-gov-early-13","level":"early","profession":"publicservice","title":"'Swamped' in numbers","scenario":"You tell your supervisor the counter is 'swamped and falling behind'. The case for help is real, but 'swamped' sounds like a mood. The arithmetic: 60-file backlog, 25 new files a day, capacity 18 a day — growing by 7 daily.","task":"Rewrite the message as the three numbers and the trend.","tips":["Backlog, inflow, capacity — the gap between the last two is the whole argument.","'Growing by 7 a day' converts a snapshot into a trajectory.","End with what one more person changes, in the same units."],"focus":["precision","impact"],"placeholder":"We're carrying a 60-file backlog with 25 new files a day against a capacity of 18 — the pile grows by 7 every day."},
    {"id":"precision-gov-early-14","level":"early","profession":"publicservice","title":"The handover with the numbers","scenario":"You're wheeling a patient into the ER and the triage nurse gets your handover. 'He's pretty rough' wastes her ten seconds. What she needs: 68-year-old male, chest pain onset 40 minutes ago, BP 90 over 60, given aspirin at 14:22.","task":"Say the handover as one tight, ordered sentence: who, what, when, vitals, treatment given.","tips":["A fixed order — age, complaint, onset, vitals, interventions — means nothing gets dropped.","Times matter clinically: onset and treatment time change what the ER does next.","Adjectives like 'rough' go last, if at all — the numbers are the picture."],"focus":["precision","structure"]},
    {"id":"precision-gov-early-15","level":"early","profession":"publicservice","title":"'Faulty hydrant' fails the next crew","scenario":"Your hydrant inspection log entry says 'hydrant 314 — faulty'. The next crew to pull up at 314 with a working fire needs to know exactly what's wrong. The specifics: the 65 mm outlet threads are stripped and the cap is seized; static pressure is normal.","task":"Rewrite the log entry so a crew reading it at 03:00 knows what works and what doesn't.","tips":["Name the failed component and the failure mode, not the verdict.","Say what still works — normal pressure changes how a crew plans around it.","Write for the reader under stress: short, physical, unambiguous."],"focus":["precision","clarity"],"placeholder":"Hydrant 314: 65 mm outlet threads stripped, cap seized — do not count on it for supply. Static pressure normal; 100 mm port serviceable."},
    {"id":"precision-gov-early-16","level":"early","profession":"publicservice","title":"The crosswalk case, counted","scenario":"You're asking the traffic section to assess a crossing near the seniors' centre. Your draft says 'lots of people cross here and cars go fast'. You spent one lunch hour counting: 47 pedestrian crossings, and radar clocked the 85th percentile at 62 in a posted 50.","task":"Rewrite the request with your counts and how you got them.","tips":["An hour of counting beats a page of adjectives.","Give the method in a clause — one lunch hour, handheld radar — so the numbers are trusted.","Match the evidence to the decision: volume plus speed is exactly what a warrant assessment weighs."],"focus":["precision","impact"],"placeholder":"In one lunch hour I counted 47 pedestrian crossings at this point, and radar showed the 85th percentile speed at 62 km/h in the posted 50."},
    {"id":"precision-gov-early-17","level":"early","profession":"publicservice","title":"'Shots nearby' pinned down","scenario":"On a night exercise you report hearing gunfire. 'Shots somewhere nearby a few minutes ago' gives your section commander nothing to plot. Your best honest estimate: three rounds, small arms, roughly 300 to 400 metres north-east, at 22:40.","task":"Say the report as one sentence: count, type, bearing, range estimate, time.","tips":["An honest range bracket beats false precision and beats vagueness — say 300 to 400, not '350' and not 'nearby'.","Bearing before range; direction is usually more reliable than distance at night.","Flag the confidence: 'estimated' is a load-bearing word here."],"focus":["precision","concision"]},
    {"id":"precision-gov-early-18","level":"early","profession":"publicservice","title":"The lunch-rush case for a second wicket","scenario":"You want the office to open a second counter over lunch. Your draft argument is 'the line gets really bad around noon'. The queue system exports the truth: average wait 6 minutes at 09:00, 34 minutes between 12:00 and 14:00.","task":"Write two sentences: the numbers, then the bounded ask they justify.","tips":["The contrast does the arguing: 6 minutes versus 34.","Bound the ask to match the evidence — a second wicket 12:00 to 14:00, not 'more staff'.","Say what success looks like in the same metric: waits back under 15."],"focus":["precision","impact"],"placeholder":"Average wait at 09:00 is 6 minutes; between 12:00 and 14:00 it's 34. A second wicket over those two hours would bring lunch waits back under 15."},
    {"id":"precision-gov-early-19","level":"early","profession":"publicservice","title":"'As soon as possible' is not a time","scenario":"A resident with a blocked driveway asks when the crew will come, and you hear yourself say 'as soon as possible'. She'll now call every hour. The dispatch board says the real answer: today between 14:00 and 17:00.","task":"Rewrite the answer with the window and the fallback if it slips.","tips":["A window she can plan around stops the callbacks; 'ASAP' invites them.","Give the fallback honestly: if the crew is pulled to an emergency, first thing tomorrow.","Only promise windows the board actually supports."],"focus":["precision","audience"],"placeholder":"The crew is scheduled for your street today between 2 and 5. If they get pulled to an emergency, you're first on the list tomorrow morning."},
    {"id":"precision-gov-early-20","level":"early","profession":"publicservice","title":"The overtime claim, dated","scenario":"Your overtime claim was queried and your first defence is 'I've been staying late constantly this month'. Your notebook has the real record: four dates, the hours on each, and which file kept you there.","task":"Rewrite the justification as the dated list a skeptical reviewer would accept.","tips":["'Constantly' is deniable; June 4, 6, 11, and 17 with hours attached is not.","Tie each date to the work: the file number or task makes it audit-proof.","Totals at the end: 9.5 hours across four dates."],"focus":["precision","structure"],"placeholder":"The claim covers four dates: June 4 (2 hrs, file B-2231), June 6 (1.5 hrs, same file), June 11 (3 hrs, counter close-out), June 17 (3 hrs, audit prep) — 9.5 hours total."},
    {"id":"precision-gov-early-21","level":"early","profession":"publicservice","title":"What 'secured the scene' means","scenario":"Your report says 'the scene was secured'. Six months later at trial, that sentence has to carry detail you no longer remember. What you actually did: taped a perimeter at the fence line and the alley mouth, started an entry log at 03:10, posted one officer at each opening.","task":"Rewrite the sentence so it records what 'secured' physically meant.","tips":["Replace the verb of conclusion with the actions: taped, logged, posted.","Boundaries by landmark: the fence line, the alley mouth — a stranger could redraw your perimeter.","The entry-log start time is the detail that wins the argument later."],"focus":["precision","structure"],"placeholder":"I established a tape perimeter at the fence line and the alley mouth, posted Constable Reyes at each opening, and started the entry log at 03:10."},
    {"id":"precision-gov-early-22","level":"early","profession":"publicservice","title":"The smell you can act on","scenario":"Your notes from a warehouse call say 'strong chemical smell throughout'. The hazmat officer reading them needs more: a solvent-like smell, strongest at the loading door, two staff with watering eyes, no visible spill or staining.","task":"Rewrite the note with character, location, effects, and what you did not find.","tips":["Describe the smell by comparison — solvent-like, rotten-egg, ammonia — not by intensity alone.","Where it's strongest is a pointer to the source; record it.","Negative findings ('no visible spill') are evidence too — they narrow the search."],"focus":["precision","clarity"],"placeholder":"Solvent-like odour, strongest at the north loading door; two staff reported watering eyes; no visible spill, staining, or damaged containers found."},
    {"id":"precision-gov-early-23","level":"early","profession":"publicservice","title":"'Much better' measured","scenario":"Your one-month report on the new intake process says it's 'working much better'. The manager deciding whether to roll it out to two other offices needs the before and after: average wait down from 40 minutes to 15, form errors from 12 a week to 3.","task":"Rewrite the assessment as the two before/after pairs.","tips":["'Better' persuades no one to spend money; 40-to-15 does.","Pair each metric: before, after, over what period.","One honest caveat — a month is a small sample — makes the numbers more credible, not less."],"focus":["precision","impact"],"placeholder":"In the first month, average wait fell from 40 minutes to 15, and form errors dropped from 12 a week to 3."},
    {"id":"precision-gov-early-24","level":"early","profession":"publicservice","title":"Hearsay, labeled","scenario":"Your report on a garage break-in blends what you saw with what the neighbour told you: 'The suspect fled over the back fence around midnight.' You never saw anyone — the neighbour reported it. Unlabeled hearsay reads as your observation and dies in court.","task":"Rewrite the passage separating what you observed from what the neighbour stated.","tips":["Two verbs keep you honest: 'I observed' and 'Mr. Cole stated'.","Attribute the source by name — anonymous hearsay is worth even less.","Your own observations (pried hasp, footprints to the fence) go in your voice; the rest in theirs."],"focus":["precision","clarity"],"placeholder":"I observed the hasp pried from the frame and footprints leading to the back fence. Mr. Cole, the neighbour at 44, stated he saw a male climb the fence at about midnight."},
    {"id":"precision-gov-early-25","level":"early","profession":"publicservice","title":"One number, one insight","scenario":"You've been asked to put the counter's monthly stats on the team board. You have a table of 20 figures. The one thing that matters: licence renewals are up 30% since the mail-out, and everything else is flat — the team should staff for it.","task":"Write the single board sentence that carries the insight, not the table.","tips":["Data is the table; the insight is the one sentence someone acts on.","Name the likely cause in a clause — the mail-out — so it's a story, not a mystery.","End with the 'so what': what the team should do differently this month."],"focus":["clarity","impact"],"placeholder":"Renewals are up 30% since the reminder mail-out while everything else held flat — expect heavier renewal traffic through month-end."}
  ],
  "executive-presence": [
    {"id":"presence-gov-early-01","level":"early","profession":"publicservice","title":"The recommendation you were asked for","scenario":"The sergeant asked which of two foot-patrol patterns your team should run this month. Your draft reply lays out both with pros and cons and ends 'happy to go either way'. She wanted your call — you've walked both beats and you know the answer.","task":"Rewrite the closing: your pick, and the one reason it beats the other.","tips":["Presenting options without a pick hands back the work you were asked to do.","'I recommend pattern B because it covers the plaza during the break-in window' — call, then reason.","Offer the reversal condition, not a hedge: if the plaza calls stop, switch back."],"focus":["clarity","impact"],"placeholder":"I recommend pattern B: it puts us in the plaza between 20:00 and 23:00, when all three break-ins happened."},
    {"id":"presence-gov-early-02","level":"early","profession":"publicservice","title":"Fact versus your read of it","scenario":"Your occurrence report says the driver 'was lying about where he'd been that evening'. What you have: his statement puts him at home, and a fuel receipt in the console is time-stamped 22:41 across town. The inconsistency is fact; 'lying' is your inference.","task":"Rewrite the passage stating the facts, then your inference, clearly labeled as yours.","tips":["Facts and inferences carry different weight — smuggling one as the other weakens both.","'His statement is inconsistent with the receipt' is unassailable; 'he lied' is arguable.","Label the inference honestly: 'In my assessment...' — that phrase is strength, not weakness."],"focus":["precision","clarity"],"placeholder":"The driver stated he was home all evening. A fuel receipt in the console is time-stamped 22:41 at the Milton Road station. In my assessment his account is not credible."},
    {"id":"presence-gov-early-03","level":"early","profession":"publicservice","title":"The briefing line without the maybes","scenario":"At shift briefing you want the squad watching the commercial plaza. What comes out is: 'I think maybe we should possibly keep an eye on the plaza area if you get a chance.' Three qualifiers and an opt-out — nobody will change their patrol for that.","task":"Rewrite it as one direct briefing line: what to do, when, and the reason.","tips":["Count your qualifiers, then cut all of them — the facts carry the authority.","Direct doesn't mean loud: a plain imperative with a reason is enough.","Time-bound the ask so it's checkable: between 20:00 and 23:00."],"focus":["concision","impact"],"placeholder":"Give the Danforth plaza extra passes between 20:00 and 23:00 — three break-ins there this week, all in that window."},
    {"id":"presence-gov-early-04","level":"early","profession":"publicservice","title":"Calm at the tape line","scenario":"You're holding the perimeter at a two-car collision and bystanders keep pressing in for photos. Your instinct is to bark. The crowd is not hostile — just curious — and a raised voice will turn curiosity into a confrontation.","task":"Say the two sentences that move people back: the instruction, and the reason that recruits them.","tips":["Low, slow, and specific reads as command; shouting reads as panic.","Give the reason in their interest: paramedics need this lane clear to work.","Tell them where they can stand — an instruction with a destination gets followed."],"focus":["audience","impact"]},
    {"id":"presence-gov-early-05","level":"early","profession":"publicservice","title":"Signpost the verbal update","scenario":"You're catching the lieutenant in the corridor with three things: the staffing gap on nights, the pump repair status, and a question about Saturday's parade detail. Unsignposted, it will sound like one long ramble and she'll retain none of it.","task":"Give the update with a signposted opening and one sentence per item.","tips":["'Three things: staffing, the pump, and Saturday' — the map costs four seconds and doubles retention.","One sentence each; detail only if she asks.","Put the item needing her decision last and flag it as the ask."],"focus":["structure","clarity"],"placeholder":"Three things, thirty seconds: nights staffing, the pump, and a decision I need on Saturday's parade."},
    {"id":"presence-gov-early-06","level":"early","profession":"publicservice","title":"Delete 'I'm just a clerk'","scenario":"You've spotted that the new fee schedule double-charges seniors who renew by mail — a real error with real money. Your email to the program office opens: 'I'm just a counter clerk so I might be wrong about this, but...' The observation is solid; the preamble undercuts it.","task":"Rewrite the opening: the finding, stated plainly, with the evidence.","tips":["Your desk is exactly where this error is visible — that's authority, not a disclaimer.","State the finding first; invite correction at the end, once, without grovelling.","'Please check my reading of section 3' is a confident invitation; 'I might be wrong' is white noise."],"focus":["clarity","impact"],"placeholder":"The new fee schedule appears to double-charge seniors who renew by mail: section 3 applies both the base fee and the handling fee to the same transaction."},
    {"id":"presence-gov-early-07","level":"early","profession":"publicservice","title":"Own the call you made","scenario":"During yesterday's system outage you closed the counter an hour early and posted staff to take paper applications — a call within your delegated authority, and it worked. Your report reads like an apology: 'I unfortunately had to take it upon myself to...'","task":"Rewrite the paragraph as decision, reason, result — owned, not confessed.","tips":["A justified decision reported apologetically teaches your boss to doubt it.","Structure: 'I decided X because Y. Result: Z.' No 'unfortunately'.","Note the authority you acted under in a clause — it shows you knew the line and stayed inside it."],"focus":["structure","impact"],"placeholder":"At 15:00, with the system down and no ETA, I closed the counter and moved both clerks to paper intake — a call within counter-supervisor delegation. We processed 22 paper applications and no one was turned away."},
    {"id":"presence-gov-early-08","level":"early","profession":"publicservice","title":"Three commands at a dead intersection","scenario":"The traffic lights are out at a four-way and you're directing by hand and voice until the crew arrives. Long sentences die in engine noise. You need three short commands you can deliver with your voice and body agreeing.","task":"Write the three commands you'd use, each five words or fewer.","tips":["One instruction per breath: 'Eastbound — stop.' 'This lane — through.'","Point, then speak, then hold the gesture; the body signs what the voice says.","Never explain mid-intersection — clarity is the courtesy."],"focus":["concision","impact"]},
    {"id":"presence-gov-early-09","level":"early","profession":"publicservice","title":"Calibrated confidence on the stand","scenario":"At a parking tribunal, the adjudicator asks if you're certain the vehicle you ticketed at 14:10 is the same one you photographed at 14:40. You're certain of the plate match; you didn't watch it continuously in between. Overclaiming loses the case; mush loses it too.","task":"Write the 2-sentence answer: what you're certain of and why, and what you can't say.","tips":["Say what you know with full weight: same plate, both times, photographed.","Concede the gap yourself before counsel finds it — it makes the certain part stronger.","Calibration is presence: strong on the strong, plain about the limits."],"focus":["precision","clarity"],"placeholder":"I'm certain it was the same plate — I photographed it at both times and the photos are in evidence. I did not observe the vehicle continuously between 14:10 and 14:40."},
    {"id":"presence-gov-early-10","level":"early","profession":"publicservice","title":"Confident about what you know","scenario":"A resident on a flooded street asks you, the crew lead's junior, when the water will be back on. You know the repair crew arrives at 16:00; you don't know how long the fix takes. The temptation is either to guess ('probably tonight') or to shrug ('no idea').","task":"Give a 2-sentence answer that is firm on the known and honest on the unknown.","tips":["Split the answer cleanly: what's scheduled versus what's uncertain.","Give the next information point: the crew can estimate once the pipe is exposed.","A confident 'here's what I know' beats a confident guess every time."],"focus":["precision","audience"],"placeholder":"The repair crew arrives at 4 — that part is confirmed. How long the fix takes depends on what they find when they expose the pipe, and they'll be able to give you an estimate then."},
    {"id":"presence-gov-early-11","level":"early","profession":"publicservice","title":"The recruit is watching you","scenario":"You're two years in and today you're showing a new hire the counter. Your instinct is to open with 'honestly I barely know this stuff myself'. It feels modest; what she hears is that nobody here can teach her, on her most nervous day.","task":"Write your 2-sentence orientation opener: calm, owned, and honest about scope.","tips":["Own what you do know: two years at this counter is real expertise for day one.","Honesty has a confident form: 'when we hit something I can't answer, I'll show you who to ask.'","Your steadiness is the actual lesson on day one."],"focus":["audience","impact"],"placeholder":"I've worked this counter for two years and I'll get you through the ninety percent that repeats every day. For the rest, the best skill here is knowing who to ask — I'll show you that too."},
    {"id":"presence-gov-early-12","level":"early","profession":"publicservice","title":"Recommend, then stop talking","scenario":"Your memo recommending a numbered-ticket queue ends: 'but of course it's totally up to you, whatever you think is best, happy either way!' The triple back-pedal un-recommends everything above it.","task":"Rewrite the closing: the recommendation restated once, and the decision you're asking for.","tips":["End on the ask, not on an exit ramp.","Deference is shown by asking for the decision, not by dissolving your view.","'Can I get your call by Friday so we can start Monday?' — that's respectful and firm at once."],"focus":["concision","impact"],"placeholder":"My recommendation is the numbered-ticket system, starting Monday. Can I have your decision by Friday?"},
    {"id":"presence-gov-early-13","level":"early","profession":"publicservice","title":"The radio voice that slows down","scenario":"You're calling in a foot pursuit and you can hear yourself: too fast, words tumbling, dispatch asking you to repeat. Every repeat costs seconds. The fix is a forced cadence — location, direction, description, need — delivered slower than feels natural.","task":"Say the transmission in that order, at a pace dispatch never has to ask twice about.","tips":["Adrenaline says faster; the channel needs slower — one beat between elements.","Fixed order means you never have to compose under stress, only fill slots.","If you must breathe, breathe between slots, not mid-word."],"focus":["clarity","concision"]},
    {"id":"presence-gov-early-14","level":"early","profession":"publicservice","title":"Holding the line with a councillor","scenario":"A city councillor appears at your counter asking you to move a constituent's application to the front of the queue 'as a favour'. You have no authority to do it and shouldn't if you did. He's used to yes. You need a no that is respectful, immovable, and gives him a legitimate path.","task":"Write the 2-3 sentences you'd say.","tips":["The rule is your footing: queue order isn't yours to trade — say so without apology.","Give the legitimate channel: the expedite criteria and who applies them.","Courteous and immovable is the combination; either alone fails."],"focus":["audience","impact"],"placeholder":"I can't move anyone in the queue, Councillor — order of receipt isn't discretionary at this counter. What I can do is flag the file for the expedite review if it meets the criteria."},
    {"id":"presence-gov-early-15","level":"early","profession":"publicservice","title":"The evacuation knock","scenario":"A kitchen fire two doors down means this floor clears now. The resident who opens the door is in pyjamas, half-asleep, reaching for questions. You have one breath to set the tone: authority that moves her without panic that freezes her.","task":"Say the 2-3 sentences: what's happening, what she does now, the one thing she doesn't do.","tips":["Level voice, short words: 'There's a fire on this floor. You need to leave now.'","One instruction at a time — coat, stairs, left. Choices slow people down.","'Stairs, not the elevator' is the sentence that saves lives; never skip it."],"focus":["clarity","impact"]},
    {"id":"presence-gov-early-16","level":"early","profession":"publicservice","title":"'Could go either way' is a dodge","scenario":"The sergeant asks whether the Hill Street intersection warrants a red-light camera, based on the collision review you just finished. You say 'it could go either way' — but your own numbers say yes: 9 angle collisions in 18 months, 7 of them red-light runs.","task":"Write the 2-sentence answer that owns the call your data supports.","tips":["You did the review; the opinion is the deliverable, not a bonus.","Lead with the call, follow with the two strongest numbers.","If there's a genuine counterweight, name it after — as context, not camouflage."],"focus":["impact","clarity"],"placeholder":"Yes — it warrants one. Nine angle collisions in 18 months, seven of them red-light runs; that's the exact pattern cameras cut."},
    {"id":"presence-gov-early-17","level":"early","profession":"publicservice","title":"Stay in your lane, own your lane","scenario":"Your draft fire report states 'the fire was caused by careless smoking'. Cause determination belongs to the investigator, not the attending crew. But you did observe things worth recording: heaviest charring at the armchair, an ashtray on its arm, no other ignition sources evident.","task":"Rewrite the passage: your observations in full, your view labeled as preliminary and yours.","tips":["Overstepping your role costs credibility exactly where you had authority.","Observations are yours to state with confidence — location of charring, what was present.","'Consistent with' is the honest verb: observations consistent with a smoking-related origin, pending investigation."],"focus":["precision","structure"],"placeholder":"Charring was heaviest at and around the armchair on the east wall; an ashtray sat on its arm. No other ignition sources were evident. These observations are consistent with a smoking-related origin; cause determination rests with the investigator."},
    {"id":"presence-gov-early-18","level":"early","profession":"publicservice","title":"Correcting upward, calmly","scenario":"The duty inspector's email tells the counter team to require two pieces of ID for name changes. The regulation you work under says one piece plus the declaration form. Someone has to say so, and the junior person who's right beats the silence that lets errors compound.","task":"Write the 2-3 sentence reply: respectful, factual, citation attached.","tips":["Correct the instruction, not the person: 'the current reg reads...' not 'you're wrong'.","Attach the source — the section number does the arguing so you don't have to.","Offer the graceful out: 'unless there's a newer directive I haven't seen' — genuine, and it costs nothing."],"focus":["audience","clarity"],"placeholder":"Quick flag before we apply this: Regulation 12(3) currently requires one piece of ID plus the statutory declaration for name changes, not two pieces — section attached. Happy to follow a newer directive if one supersedes it."},
    {"id":"presence-gov-early-19","level":"early","profession":"publicservice","title":"The date you stand behind","scenario":"At a tense residents' meeting, someone asks you directly when Birch Road reopens. The schedule says Friday if the final paving cures on time. You can hide ('we're working hard on it'), overpromise ('Friday!'), or own a calibrated commitment.","task":"Give the 2-sentence answer: the date, and the one condition that could move it.","tips":["A date with its condition is a promise adults can hold you to — that's presence.","Name the single real risk, not a fog of maybes.","Say how they'll know if it slips: notice on the barriers by Thursday noon."],"focus":["precision","impact"],"placeholder":"Birch Road reopens Friday, with one condition: the final paving layer has to cure through two dry nights. If the weather breaks against us, we'll post the new date on the barriers by Thursday noon."},
    {"id":"presence-gov-early-20","level":"early","profession":"publicservice","title":"One apology, then the fix","scenario":"The office misplaced a resident's original birth certificate for eleven days. It's been found. Your draft response apologizes five separate times and never quite says what happens next — the grovel has swallowed the service.","task":"Rewrite: one plain apology, what happened, and exactly what happens now.","tips":["One real apology outweighs five reflexive ones.","'What happens now' is the part she actually needs: pickup today, or tracked mail tomorrow, her choice.","Steadiness after an error is what rebuilds trust; performed distress isn't."],"focus":["concision","audience"],"placeholder":"We misfiled your birth certificate and I'm sorry — that shouldn't have happened. It's been found and is secure at this office; you can collect it today until 5, or we'll send it by tracked mail tomorrow."},
    {"id":"presence-gov-early-21","level":"early","profession":"publicservice","title":"Your first morning huddle","scenario":"The crew lead is away and you're running the works-yard morning huddle for the first time: six people, three items — the Route 4 patch job, a chipper safety notice, and early quit for the long weekend. Your rehearsal keeps starting with 'um, so, I guess...'","task":"Deliver the huddle: signposted open, one line per item, tasks named to people.","tips":["Open with the map: 'Three things this morning.' Confidence is mostly structure.","Assign by name — 'Dev and Marta, Route 4' — vagueness reads as nerves.","Safety item gets the middle slot and one extra beat of silence after it."],"focus":["structure","clarity"],"placeholder":"Morning — three things. First, Route 4: Dev and Marta, you're on the patch job, truck's loaded."},
    {"id":"presence-gov-early-22","level":"early","profession":"publicservice","title":"'We don't know yet', said like a professional","scenario":"At the cordon of a gas-leak evacuation, a resident asks you what caused it and when she can go home. Cause: unknown yet. Timeline: not yours to guess. The weak versions are a shrug or a bluff. The strong version tells her what is known, what isn't, and when she'll hear more.","task":"Give the 3-sentence answer: known, unknown, next update.","tips":["Certainty about the process substitutes for certainty about the facts.","'The utility crew is on site now' is known and calming — lead with it.","Name the update mechanism: announcements at the community centre every hour."],"focus":["precision","audience"],"placeholder":"Here's what I can tell you: the utility crew is on site and the leak is isolated to the one main. We don't yet know the cause or the reopening time — I won't guess at either. Updates are announced at the community centre on the hour."},
    {"id":"presence-gov-early-23","level":"early","profession":"publicservice","title":"Neutral options are a hiding place","scenario":"The event sergeant asks which barricade layout you'd run for the street festival — the one from last year, or the new plan with a second exit lane. You wrote the incident notes last year: the single exit jammed for 20 minutes at closing. You know the answer and you're presenting both 'neutrally'.","task":"Write your answer: the pick, the incident that decides it, and the cost you're accepting.","tips":["False balance between a plan that failed and one that fixes it is not professionalism.","Cite the evidence you personally hold — your own notes from last year.","Name the tradeoff of your pick yourself (two more barriers, one more position) — owning costs is owning the call."],"focus":["impact","structure"],"placeholder":"The new layout. Last year's single exit jammed for 20 minutes at closing — it's in my notes from the night — and the second lane removes that. It costs us two more barriers and one more position, and it's worth both."},
    {"id":"presence-gov-early-24","level":"early","profession":"publicservice","title":"The second ask, firmer, still yours","scenario":"You asked a driver to move his car off the hydrant zone and he waved you off without looking up from his phone. The second approach has to change something — firmer, specific, consequence named — without you borrowing anger you'll have to own later.","task":"Say the second version: the instruction, the timeframe, the consequence, level tone.","tips":["Escalate the content, not the volume: 'now' and the ticket amount do the work.","Give one clean choice: move it now, or it's a ticket and a tow.","Deliver it and stop talking — silence after a clear instruction is pressure."],"focus":["audience","impact"]},
    {"id":"presence-gov-early-25","level":"early","profession":"publicservice","title":"Testimony-proof your own prose","scenario":"Court prep, and the prosecutor reads your report back to you: 'I would have then proceeded to make my way towards the vehicle in question.' Passive, conditional, padded — it sounds evasive read aloud, and you weren't evading anything. You walked to the car and looked in the window.","task":"Rewrite one paragraph of report prose into first-person, active, definite sentences.","tips":["'I walked to the car' survives being read aloud; 'proceeded to make my way' doesn't.","'Would have' implies you don't remember — write what you did, or write that you don't recall.","Read the rewrite aloud; anywhere you wouldn't say it, fix it."],"focus":["clarity","precision"],"placeholder":"I walked to the car and looked through the driver's window. The key was in the ignition and the engine was cold."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-gov-early-01","level":"early","profession":"publicservice","title":"Before or after — answer it","scenario":"On the stand, defence counsel asks: 'Did you caution my client before or after you searched the bag?' You cautioned him before — you know this from your notes. Your instinct is to start explaining the whole stop from the beginning, which sounds like stalling.","task":"Write the direct answer, then the one supporting fact.","tips":["Answer the actual question in the first word: 'Before.'","Then anchor it: 'My notebook records the caution at 15:22, the search at 15:26.'","Narrating the whole stop when asked a two-option question reads as evasion."],"focus":["clarity","precision"],"placeholder":"Before. My notebook records the caution at 15:22 and the search at 15:26."},
    {"id":"pressure-gov-early-02","level":"early","profession":"publicservice","title":"'Why did it take twenty minutes?'","scenario":"At a community meeting after a break-in spree, a resident stands up: 'Why did it take twenty minutes for anyone to show up?' The room goes quiet. The true answer: both cars were on a serious collision across town. The defensive answer — 'we can't be everywhere' — will lose the room.","task":"Give the 2-3 sentence answer: the fact first, no defensiveness, then what's being done.","tips":["Answer the question asked: 'Both units were at an injury collision on Route 9.' That's an answer, not an excuse.","Skip 'you have to understand' — they don't have to, and it sounds like blame.","Close with the forward piece: what changes, or what to do while waiting."],"focus":["audience","clarity"],"placeholder":"That night both of our cars were at an injury collision on Route 9 — that's the honest answer for the twenty minutes."},
    {"id":"pressure-gov-early-03","level":"early","profession":"publicservice","title":"'Why isn't this in your report?'","scenario":"The sergeant has your report open: 'The complainant says she told you about a previous incident. Why isn't that in here?' She did tell you, and you left it out — an omission, not a judgment call. Explaining around it will dig the hole deeper.","task":"Write the direct response: own it, then the fix and the timeline.","tips":["'It should be. She did tell me and I left it out.' Ownership in one breath.","The fix, immediately after: a supplementary report filed today.","No 'to be fair' and no autopsy of why — unless asked, and then briefly."],"focus":["clarity","impact"],"placeholder":"It should be in there — she did tell me and I missed it. I'll file a supplementary report before end of shift."},
    {"id":"pressure-gov-early-04","level":"early","profession":"publicservice","title":"The rule you don't know","scenario":"A counter applicant asks whether her foreign marriage certificate needs an authenticated translation or a notarized one. You genuinely don't know — the rule changed recently — and guessing could cost her a wasted $200. Bluffing and shrugging both fail her.","task":"Write the 2-sentence answer: the honest gap, and exactly how and when you'll close it.","tips":["'I don't know' paired with a plan reads as competence, not weakness.","Be specific about the path: 'I'll confirm with the registrar and call you before 4 today.'","Never guess where a wrong answer costs the citizen money."],"focus":["clarity","precision"],"placeholder":"The translation rule changed recently and I won't guess on it — a wrong answer costs you real money. I'll confirm with the registrar this afternoon and call you before 4."},
    {"id":"pressure-gov-early-05","level":"early","profession":"publicservice","title":"'Is he going to be okay?'","scenario":"You're doing compressions in a living room and the patient's wife, held back at the doorway, asks: 'Is he going to be okay?' You can't stop, you can't promise, and you can't ignore her. There is a sentence that is honest, kind, and takes three seconds.","task":"Say the one or two sentences you'd give her without breaking rhythm.","tips":["Honest and kind can coexist: 'He's very sick. We're doing everything for him right now.'","Never promise an outcome you don't control; false hope collapses hardest.","Give her a task if you can — it helps her and you: 'Can you get his medication list?'"],"focus":["audience","concision"]},
    {"id":"pressure-gov-early-06","level":"early","profession":"publicservice","title":"Three questions from dispatch, in order","scenario":"You've called in a warehouse alarm and dispatch fires back three questions at once: any signs of entry, how many access points, do you need a second unit. Under the adrenaline your instinct is to answer the last one you heard and lose the other two.","task":"Say the reply that answers all three, in the order asked, one clause each.","tips":["Answer in the order asked — it lets dispatch tick boxes without re-asking.","One clause per answer; elaboration comes after all three are done.","If one answer is 'unknown yet', say that word — silence on one item restarts the loop."],"focus":["structure","concision"]},
    {"id":"pressure-gov-early-07","level":"early","profession":"publicservice","title":"The reporter at the apparatus bay","scenario":"You're rolling hose after a warehouse fire when a reporter walks up: 'Firefighters are saying the building wasn't up to code — was it?' Cause and code are the investigator's file, not yours, and 'no comment' will be the quote under your photo.","task":"Give the 2-sentence answer that is honest, calm, and hands her the right door.","tips":["Not knowing officially is different from hiding: 'code review is the fire marshal's determination, and it's underway.'","Offer the real channel with a real timeline — the marshal's office issues findings, media line responds same-day.","Say nothing speculative with a recorder out; a wrong guess follows the file forever."],"focus":["audience","clarity"],"placeholder":"Code compliance is the fire marshal's determination and that review is underway — anything I said now would be a guess, and you deserve better than my guess."},
    {"id":"pressure-gov-early-08","level":"early","profession":"publicservice","title":"The third 'when will it be done?'","scenario":"The same applicant is at your counter for the third time asking when his fence permit will be done. Last visit you said two weeks; a referral to the utilities desk added time. He's entitled to be irritated, and your irritation would be less forgivable than his.","task":"Write the answer: the direct date, what changed since last time, and the proactive close.","tips":["Answer the question before the explanation: 'the 18th' comes first.","Name what changed — the utility referral — so the moved date isn't a broken promise, it's a new fact.","Close the loop yourself: 'I'll call you the day it clears so you don't have to come in.'"],"focus":["audience","precision"],"placeholder":"Your permit should clear on the 18th. Since your last visit it picked up a mandatory utilities review — that's the added week — and I'll call you the day it's done so you're not making another trip."},
    {"id":"pressure-gov-early-09","level":"early","profession":"publicservice","title":"Holding the capacity line","scenario":"You refused an event permit because the hall's fire capacity is 180 and the organizer sold 240 tickets. He's on the phone, loud, invoking his fifteen years of running this event. Your reason is not a judgment call — it's a number — and folding would put 60 people over a fire limit.","task":"Write the 2-3 sentence response that holds, with the number doing the work.","tips":["Meet pressure with the fact, not with matching volume: 180 is the limit, 240 is the sales.","Acknowledge his stake without moving: fifteen good years don't change this year's arithmetic.","Give the path that says yes: a bigger venue, or capped attendance — the no is to the number, not to him."],"focus":["impact","precision"],"placeholder":"The hall's fire capacity is 180 and you've sold 240 — I can't sign a permit that puts 60 people over that line. Cap the tickets at 180 or move to the arena hall, and I can approve it same day."},
    {"id":"pressure-gov-early-10","level":"early","profession":"publicservice","title":"'Would you do anything differently?'","scenario":"In the debrief after a rough medical call, the chief asks you directly: 'Would you do anything differently?' Something honest exists: you'd have staged the stretcher closer before starting the carry. The trap on one side is 'no, nothing'; on the other, unravelling into self-flagellation.","task":"Write the 2-sentence answer: the one specific thing, and what you'll change.","tips":["One concrete improvable beats both 'nothing' and a confession spiral.","Frame it as learned, not as failed: 'next time the stretcher stages at the bottom of the stairs first.'","Answering this well is how juniors earn harder calls — it's a trust question in disguise."],"focus":["clarity","impact"],"placeholder":"One thing — I'd stage the stretcher at the bottom of the stairs before we started the carry. It cost us about ninety seconds and I'll set it up that way next time."},
    {"id":"pressure-gov-early-11","level":"early","profession":"publicservice","title":"Yes-or-no, with one asterisk","scenario":"At a council committee, a councillor asks you point blank: 'Did the crew follow the closure procedure that night — yes or no?' They did, with one deviation: the advance sign went up 40 metres short of standard. A bare 'yes' will be contradicted later; a ramble sounds like a cover-up.","task":"Write the answer: the direct yes, the one deviation, stated in the same breath.","tips":["'Yes, with one exception, which I'll state' — direct and complete beats direct alone.","Quantify the deviation precisely; vagueness about it reads as concealment.","Volunteering the flaw yourself is what makes the rest of your testimony credible."],"focus":["clarity","precision"],"placeholder":"Yes, with one exception I should state: the advance warning sign was placed 40 metres short of the standard distance. Every other step followed procedure."},
    {"id":"pressure-gov-early-12","level":"early","profession":"publicservice","title":"'That's not what I asked'","scenario":"Mid-answer at your performance board, the inspector cuts in: 'That's not what I asked. I asked why the file sat for nine days.' You'd been describing the intake process. The recovery matters more than the stumble — no wounded pause, no launching into a defence.","task":"Say the recovery: brief acknowledgment, then the direct answer to the actual question.","tips":["Two words of acknowledgment, maximum: 'Fair — directly:' then answer.","Don't re-explain what you meant; answer what they asked.","An interruption is information about what they need — use it, don't fight it."],"focus":["clarity","concision"]},
    {"id":"pressure-gov-early-13","level":"early","profession":"publicservice","title":"The stat you don't have on you","scenario":"In the operations meeting, the deputy asks how many false alarms your station ran last month. You don't have the number. You do know the shape of it — high twenties most months. Inventing '27' is a trap; 'no idea' undersells what you do know.","task":"Write the answer: the honest bracket, labeled as such, and the exact figure by when.","tips":["Bracket honestly: 'high twenties is the recent pattern — I'll confirm the exact count.'","Label the estimate as an estimate; the room will remember whichever number you say.","Commit to a time for the real figure: 'exact number to you by 2 PM.'"],"focus":["precision","clarity"],"placeholder":"I don't have the exact count with me — recent months have run in the high twenties. I'll pull last month's figure and have it to you by 2."},
    {"id":"pressure-gov-early-14","level":"early","profession":"publicservice","title":"The complaint reply that stops arguing","scenario":"A landlord has filed a written complaint about your rental inspection, disputing six points. Your draft reply argues all six, line by line, in an increasingly clipped tone. Buried in his letter is the core question: does he have to replace the panel, or just the two breakers?","task":"Rewrite the reply to answer the core question first, then address only what still matters.","tips":["Under attack, find the question inside the complaint and answer it first.","Conceding minor points costs nothing and buys credibility: two of his six are fair.","Every point you argue that didn't need arguing extends the fight by a letter."],"focus":["concision","audience"],"placeholder":"To your central question: only the two breakers must be replaced, not the panel — the panel itself passed."},
    {"id":"pressure-gov-early-15","level":"early","profession":"publicservice","title":"Two questions wearing one sentence","scenario":"An agitated resident at the counter asks: 'Why is the pool closed again and when is it actually going to open, because this is the third time this summer?' That's two questions and a grievance. Answering only one guarantees the other comes back louder.","task":"Write the answer that splits and answers both, in order, then meets the grievance.","tips":["Name the split: 'Two answers: why, and when.'","Answer 'when' with a date, not 'soon' — under pressure, vagueness reads as stonewalling.","The grievance gets one honest sentence, not a rebuttal: three closures in a summer is a fair complaint."],"focus":["structure","clarity"],"placeholder":"Two answers. Why: a pump seal failed yesterday and the water can't circulate safely. When: the part arrives Thursday and we reopen Friday morning — and you're right that three closures in one summer isn't good enough."},
    {"id":"pressure-gov-early-16","level":"early","profession":"publicservice","title":"Under oath and genuinely unsure","scenario":"Counsel asks what time you left the scene. Your report covers arrival but not departure, and you honestly don't remember — it was eight months ago. Guessing under oath is how good cases die. Not remembering, said precisely, is a perfectly strong answer.","task":"Write the answer: what you don't recall, what you do, and where a record might exist.","tips":["'I don't recall' is testimony, not failure — deliver it at full volume, not as a mumble.","Fence the gap with what you do know: after the tow, before end of shift at 19:00.","Point to the record: the CAD log would show when I cleared."],"focus":["precision","clarity"],"placeholder":"I don't recall the exact time. It was after the tow truck left and before my shift ended at 19:00 — the CAD log would show precisely when I cleared the scene."},
    {"id":"pressure-gov-early-17","level":"early","profession":"publicservice","title":"Finding the question inside 'you people'","scenario":"A man at the works counter opens with: 'You people never fix anything on the east side — you don't care about us.' Inside the broadside is an answerable question: what's happening about the east-side roads? Arguing with the framing loses; answering the buried question can land.","task":"Write the 2-3 sentence response that skips the bait and answers what's underneath.","tips":["Don't defend 'you people' — answer 'what about the east side'.","Bring one checkable fact: Carlton Street resurfacing starts the 12th.","If his specific street isn't on the list, say so straight — respect beats spin with an angry audience."],"focus":["audience","impact"],"placeholder":"Let me tell you what's actually scheduled east of the river: Carlton Street resurfacing starts the 12th, and the Dunn Avenue drainage job follows in August."},
    {"id":"pressure-gov-early-18","level":"early","profession":"publicservice","title":"'Why should I talk to you?'","scenario":"You're canvassing door-to-door after a string of garage break-ins. A resident answers the door with arms crossed: 'Why should I tell you anything? Nothing happens with it anyway.' You have thirty seconds and a real answer — the last arrest on this street came from a doorstep tip.","task":"Say the 2-sentence answer that takes the challenge seriously and gives the real reason.","tips":["Meet the challenge as a fair question, because it is one.","One concrete instance beats a speech: the March arrest started as a neighbour's doorstep description.","Make the ask small: two questions, one minute, no statement required today."],"focus":["audience","clarity"]},
    {"id":"pressure-gov-early-19","level":"early","profession":"publicservice","title":"'Did it fail?' — it failed","scenario":"An applicant calls about her food-handler certification exam and asks flat out: 'Did I fail?' She did — by two points — and she can rewrite in two weeks. The kind-feeling move is to open with the rewrite policy; the actually kind move is to answer her question first.","task":"Write the response: the direct answer, the margin, and the path, in that order.","tips":["She asked a yes/no question — the first word should answer it.","The margin matters: two points reframes 'failed' as 'nearly there'.","The path lands better after the truth than instead of it."],"focus":["clarity","impact"],"placeholder":"Yes — you missed the pass mark by two points. You can rewrite in two weeks, and with a margin that small I'd book it today."},
    {"id":"pressure-gov-early-20","level":"early","profession":"publicservice","title":"'Is the pump serviceable or not?'","scenario":"Two minutes into your equipment briefing, the captain cuts you off: 'Stop — is the pump serviceable or not?' It is, with one caveat: the pressure-relief valve is sticking and a replacement lands Thursday. The answer is one word plus one clause, and you were four paragraphs from it.","task":"Say the answer: the verdict first, the single caveat, and stop.","tips":["When command asks binary, answer binary: 'Serviceable.'","One caveat, one clause: 'the relief valve sticks — replacement Thursday.'","Then silence. Resuming the briefing you were giving is answering a question nobody asked."],"focus":["concision","clarity"]},
    {"id":"pressure-gov-early-21","level":"early","profession":"publicservice","title":"'Did you send the wrong notice?'","scenario":"Your supervisor holds up a returned letter: 'Did you send the demolition notice to the wrong address?' You did — transposed digits, 214 instead of 241 — and you caught it this morning and already have the corrected notice ready to go. The answer is yes, and the yes comes first.","task":"Write the response: the admission, the cause in one clause, and the containment.","tips":["'Yes' before context — reversed order sounds like a wriggle.","Cause in five words: transposed digits on the address.","The containment is your real answer: corrected notice ready, wrong recipient called, deadline unaffected."],"focus":["clarity","impact"],"placeholder":"Yes — I transposed the digits, 214 for 241. I caught it this morning: the corrected notice is ready to send today, I've called the household that got it in error, and the statutory deadline still holds."},
    {"id":"pressure-gov-early-22","level":"early","profession":"publicservice","title":"The 'hypothetically' trap","scenario":"A frustrated homeowner at the permit counter leans in: 'So hypothetically, if I just built the deck without the permit, what happens?' It's not hypothetical and you both know it. The answer that serves him is the real consequence chain, delivered without threat or wink.","task":"Write the answer: the honest consequences, flat and factual, then the better path.","tips":["Answer the real question under the hypothetical — that's not a gotcha, it's respect.","Consequences as facts, not threats: stop-work order, double fees, and it surfaces at sale time.","End on the comparison that decides it: the permit is $180 and ten days; the other road is more of both."],"focus":["precision","audience"],"placeholder":"I'll answer it straight: an unpermitted deck gets a stop-work order when it's spotted, the permit fee doubles, and it comes up on every future sale of the house. The permit is $180 and about ten days — it's the cheaper path by a wide margin."},
    {"id":"pressure-gov-early-23","level":"early","profession":"publicservice","title":"The beat before the answer","scenario":"Promotion board, and the hardest question yet: 'Tell us about a decision you got wrong.' Your habit under pressure is to start talking immediately — 'um, so, basically' — and compose out loud. The stronger move costs two seconds: silence, one breath, then a first sentence that answers.","task":"Practice the pattern aloud: the pause, then a first sentence that names your example directly.","tips":["Two seconds of silence reads as thought; six 'basicallys' read as panic.","Use the pause to pick the example, not to draft the speech.","Your first sentence should name the incident: 'The Meadowvale detour, last October.'"],"focus":["concision","structure"]},
    {"id":"pressure-gov-early-24","level":"early","profession":"publicservice","title":"The 03:00 call from the duty officer","scenario":"The duty officer calls you at 03:00 about the arrest you processed at midnight — a councillor's son, and it's already in the news. He's not chatting; he needs three things fast: what happened, what's the charge status, is there anything non-standard about the file.","task":"Give the three answers in that order, one sentence each, no warm-up.","tips":["At 03:00, skip the preamble — he called you, so start with item one.","One sentence per item; he'll drill into whatever he needs more of.","'Nothing non-standard' is a complete and valuable answer to the third question — if it's true."],"focus":["structure","concision"],"placeholder":"Three things: he was arrested at 23:40 for impaired driving after a single-car collision on Grove, no injuries. Charges are laid and he was released on an undertaking, court date the 14th. Nothing non-standard — the file is clean and the tape covers the whole stop."},
    {"id":"pressure-gov-early-25","level":"early","profession":"publicservice","title":"'Are we safe?' after the spill","scenario":"At the public meeting following a tanker rollover, a mother with a stroller asks the only question that matters: 'Is my family safe?' The honest answer is yes with one live caveat — air testing is clear, but the creek stays off-limits pending water results Friday. Fudging either half fails her.","task":"Write the answer: the direct yes, its basis, and the one caveat with its date.","tips":["Answer the question first: 'Yes — with one exception I'll spell out.'","Basis makes the yes trustworthy: forty-eight hours of clear air tests, named agency.","The caveat is a gift, not a hedge: stay out of the creek until Friday's results — precise beats reassuring."],"focus":["audience","precision"],"placeholder":"Yes, your family is safe — with one exception I want to be exact about. Air testing has been clear for 48 hours across the whole neighbourhood. The creek is the exception: keep kids and pets out of it until the water results come back Friday."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-gov-early-01","level":"early","profession":"publicservice","title":"The crosswalk, before and after","scenario":"You're writing to the traffic committee about the crossing outside the seniors' centre. Your draft is a data dump: counts, speeds, sightline measurements. Data informs; what moves a committee is the change story — what this corner is now, what it becomes with a signal, and the bridge between.","task":"Write a 3-4 sentence recommendation framed as before, after, and the bridge.","tips":["Before: forty-seven crossings an hour against traffic running 62 in a 50.","After: the same corner with a signalized crossing — name what stops happening.","The bridge is the ask: one pedestrian signal, budget line, installed by fall."],"focus":["structure","impact"],"placeholder":"Today, 47 people an hour cross at this corner against traffic running 62 in a posted 50 — most of them from the seniors' centre. With a signalized crossing, that same corner becomes a protected crossing point on their only route to the shops."},
    {"id":"narrative-gov-early-02","level":"early","profession":"publicservice","title":"The incident as a story that holds","scenario":"Your court brief on a shoplifting arrest reads like shuffled index cards — observations, times, and statements in the order you wrote them down, not the order that makes the case make sense. The prosecutor needs the narrative spine: scene, observation, action, outcome.","task":"Rewrite the summary as a 4-sentence narrative in that order, every fact kept.","tips":["Chronology is the reader's handrail — set the scene in one sentence, then move forward in time only.","Each sentence should force the next: watched, approached, arrested, recovered.","A clean narrative isn't spin; it's the same facts in the order a stranger can follow."],"focus":["structure","clarity"],"placeholder":"At 16:20 I was on foot patrol in the Bay Street mall when the manager of Halton's flagged me down. She pointed out a male she had watched conceal two power tools under his coat."},
    {"id":"narrative-gov-early-03","level":"early","profession":"publicservice","title":"The smoke alarm refusal","scenario":"You're doing fire-prevention visits and the man at the door waves off the free smoke alarm: 'Lived here forty years, never had a fire.' The statistics you're armed with will bounce off him. What might not: last month's kitchen fire on Delia Street, where the alarm woke the family at 04:00.","task":"Say the 2-3 sentences you'd use — one nearby story, his stakes, the two-minute ask.","tips":["A house two streets over beats a national statistic every time.","His forty fire-free years is the setup, not the obstacle: the Delia Street family had thirty-eight.","Shrink the ask to nothing: two minutes, my ladder, no cost, and I'm gone."],"focus":["audience","impact"],"placeholder":"Fair enough — forty years is a good run. The family on Delia Street had thirty-eight before last month's kitchen fire, and the alarm we'd installed that spring woke them at four in the morning."},
    {"id":"narrative-gov-early-04","level":"early","profession":"publicservice","title":"The case for a second clerk","scenario":"You're pitching your manager for a second counter clerk at peak hours. Your draft leads with how tired the team is — true, but it reads as complaint. The persuasive frame: what residents experience now, what changes, and the objection ('no budget') answered before she raises it.","task":"Write a 4-sentence pitch: the now, the after, the cost, and the objection pre-empted.","tips":["Frame it as the resident's experience: 34-minute lunch waits, people leaving without service.","Pre-empt the budget objection yourself: four hours a day of existing part-time allocation, not a new hire.","End on the ask with a trial shape: three weeks, then review the wait data together."],"focus":["structure","impact"],"placeholder":"Right now a resident who comes at lunch waits 34 minutes, and every day a few give up and leave — those become callbacks and complaints. With a second wicket over the two peak hours, waits come back under 15."},
    {"id":"narrative-gov-early-05","level":"early","profession":"publicservice","title":"The compliance letter that persuades","scenario":"You're writing to a homeowner about a lot so overgrown it blocks the sidewalk sightline at the corner. The template leads with the bylaw number and the fine schedule — which gets grudging, minimal, slow compliance. The persuasive version leads with why it matters and how easy the fix is.","task":"Rewrite the letter's first three sentences: the real-world stake, the specific ask, the easy path.","tips":["The stake is human, not legal: drivers can't see children stepping off that corner.","Make the ask physical and finite: the hedge cut back to the property line, one weekend's work.","Keep the enforcement line, but last and brief — the door held open, not the lead."],"focus":["audience","impact"],"placeholder":"The hedge at your corner has grown past the sidewalk, and drivers turning onto Freeman can no longer see anyone stepping off the curb — including the kids walking to St. Michael's each morning."},
    {"id":"narrative-gov-early-06","level":"early","profession":"publicservice","title":"Answer 'they still work' before it's said","scenario":"You're requesting replacement of the station's portable radios. Everyone knows the objection coming: 'they still work.' Mostly true — which is why your memo has to raise it first and answer it: 14 dead-battery failures logged in six months, two during working incidents.","task":"Write a 3-sentence passage that states the objection fairly, then answers it with the log.","tips":["Raise the strongest objection yourself — it shows the committee you're not hiding from it.","State it fairly before answering; a strawman persuades no one.","The two failures during live incidents are the argument; lead the answer with them."],"focus":["structure","impact"],"placeholder":"The fair objection is that the current radios still work — and most days, they do. The maintenance log tells the rest: fourteen dead-battery failures in six months, two of them during working incidents."},
    {"id":"narrative-gov-early-07","level":"early","profession":"publicservice","title":"One file that stands for forty","scenario":"You're proposing an expedited-review lane for hardship cases. Your draft argues in categories and criteria. What will actually move the review board is one anonymized file — the applicant whose utility shutoff beat her paperwork by two days — plus the number of files like hers last quarter.","task":"Write a 3-4 sentence passage: the one story, then the count it represents.","tips":["One specific person makes the category real; the count makes it a pattern, not an anecdote.","Keep the story to verifiable facts from the file — persuasion built on embellishment collapses in review.","Land on the ratio: forty-one files met hardship criteria last quarter; the standard queue served none of them in time."],"focus":["audience","impact"],"placeholder":"File 2214: a single mother whose expedite-worthy application sat in the standard queue while her utility shutoff notice ran its clock — the power went off two days before her approval came through."},
    {"id":"narrative-gov-early-08","level":"early","profession":"publicservice","title":"Selling the new form to the team","scenario":"Head office is replacing the intake form and your team hates change. Announcing it as a directive gets malicious compliance. The persuasive version paints Tuesday morning as it is now — the double entry, the callback pile — and Tuesday morning as it will be.","task":"Write the 3-4 sentence team message framed as before and after, in their day's terms.","tips":["Describe the pain they already complain about — you're narrating their Tuesday, not head office's slide deck.","The after must be concrete: one entry instead of two, and the address errors that cause callbacks disappear at the source.","Be honest about the cost — two clunky weeks — because they'll find out anyway."],"focus":["clarity","impact"],"placeholder":"You know the worst part of Tuesdays: every application typed twice, and the callback pile from address errors. The new form kills both — one entry, and the address field validates itself."},
    {"id":"narrative-gov-early-09","level":"early","profession":"publicservice","title":"The evacuation notice people obey","scenario":"The river will crest Thursday and your voluntary evacuation notice for the low streets is competing with every resident's optimism. The draft is procedural — zones, routes, shelter addresses. It's missing the sentence that moves people: what the water did in 2019, and by when they must decide.","task":"Write the notice's first three sentences: the concrete stake, the deadline, the action.","tips":["The 2019 mark — water over a metre deep on these same streets in six hours — beats any adjective.","'Decide by Wednesday dark' does what 'residents are encouraged to consider' never will.","One action, stated plainly: leave Wednesday, and here is where you go."],"focus":["audience","impact"],"placeholder":"The river will crest Thursday at or above the 2019 flood line — the year these streets took over a metre of water in six hours. If you plan to leave, leave by dark on Wednesday, while the roads out are still dry."},
    {"id":"narrative-gov-early-10","level":"early","profession":"publicservice","title":"Making the drain program interesting","scenario":"You're writing the budget-committee paragraph for the storm-drain clearing program — the least glamorous line item on the page. Framed as maintenance, it gets cut. Framed as the eleven flooded basements on Aldous Street the year the program lapsed, it survives.","task":"Write the 3-sentence paragraph that translates the program into what it prevents.","tips":["Boring programs are prevention stories told badly — tell the disaster it prevents instead.","Use the year it lapsed as your natural experiment: same streets, same storms, eleven claims.","Put the program cost next to the claims cost and let the arithmetic argue."],"focus":["impact","clarity"],"placeholder":"This line buys the autumn drain-clearing that keeps Aldous Street basements dry. The one year it lapsed, the same October storms put water in eleven basements — claims that cost four times the program."},
    {"id":"narrative-gov-early-11","level":"early","profession":"publicservice","title":"The reluctant witness","scenario":"The only witness to a hit-and-run doesn't want to get involved — court dates, time off work, 'it won't matter anyway'. Lecturing her about civic duty will end the conversation. What might work: what her statement specifically changes, and what the process actually costs her.","task":"Write the 3-sentence ask: her specific value, the honest cost, the support available.","tips":["Make her singular: she's the only person who saw the plate — without her there is no case, with her there likely is.","Deflate the imagined cost with the real one: a written statement today; most cases like this never reach trial.","Answer 'it won't matter' with what happened last time: the cyclist's medical bills turned on exactly this kind of statement."],"focus":["audience","impact"],"placeholder":"You're the only person who saw the plate — without you there's no case to bring, and with you there almost certainly is. The real cost is smaller than you'd guess: a written statement today, and most of these resolve without anyone testifying."},
    {"id":"narrative-gov-early-12","level":"early","profession":"publicservice","title":"Three complaints, one argument","scenario":"Three separate 311 complaints about missed collection on Harrow Lane sit in your queue. Individually they're tickets to close. Together they're an argument: the new route timing puts the truck there before residents' bins are out. You're writing to the route planner.","task":"Write a 3-4 sentence note that turns the three tickets into the pattern and the fix.","tips":["Stack the tickets into a shape: three misses, same street, all since the March route change.","Name the mechanism, not just the correlation: the truck now passes at 06:40; bylaw lets bins go out at 06:00.","The fix falls out of the story — swap Harrow to the route's back half — so the ask feels inevitable."],"focus":["structure","impact"],"placeholder":"Three missed-collection complaints on Harrow Lane since March aren't three problems — they're one. The route change moved the truck's pass to 06:40, and bylaw doesn't allow bins out before 06:00."},
    {"id":"narrative-gov-early-13","level":"early","profession":"publicservice","title":"The job-fair pitch","scenario":"You have two minutes at a college job fair to interest students in paramedic work. The benefits-and-requirements recitation empties the table. What fills it: one true call — the save, or the small human moment — and the honest shape of the work around it.","task":"Say the 2-minute pitch: one story, the honest hard part, the first step.","tips":["Lead with a specific call you can tell in five sentences — story is the only thing that outcompetes a phone screen.","Tell the hard part unprompted: nights, and calls that stay with you. Honesty recruits the right people.","End with a step they can take this week, not a brochure."],"focus":["audience","impact"]},
    {"id":"narrative-gov-early-14","level":"early","profession":"publicservice","title":"The 'why this matters' paragraph","scenario":"Your playground inspection found rusted swing chains at three parks — technically reportable as 'corrosion exceeding tolerance'. Filed in those words, it queues behind everything. Your report needs one paragraph that makes a busy parks manager feel the stakes without inflating them.","task":"Write the 3-sentence stakes paragraph: what fails, what happens when it does, why now.","tips":["Translate 'corrosion exceeding tolerance' into the event: a chain lets go mid-swing.","Calibrate honestly — no one's died, and the season's heaviest use starts in three weeks. Both facts belong.","The 'why now' is the schedule: replacement takes a week, and school's out on the 28th."],"focus":["impact","clarity"],"placeholder":"The rusted links at these three parks are the kind that fail suddenly, mid-swing, under a child's weight — not gradually where anyone sees it coming. Nothing has failed yet, and peak season starts when school lets out on the 28th."},
    {"id":"narrative-gov-early-15","level":"early","profession":"publicservice","title":"Persuading the twenty-year veteran","scenario":"Your patrol partner of twenty years' service refuses to touch the new e-ticketing, doubling your roadside times while he handwrites. Policy citations bounce off him. What might land: what the system does for him — his handwriting disputes, his court no-shows on illegible tickets, his hour of end-of-shift transcription.","task":"Write the 2-3 sentences you'd actually say to him, built on his stakes.","tips":["Persuade from his ledger, not the department's: it's his hour of transcription it deletes.","Pick his sorest spot — the ticket tossed last month over handwriting — and hang the case on it.","Offer the low-pride path in: run it together on the next three stops, and he can go back if he hates it."],"focus":["audience","impact"],"placeholder":"Forget head office — this thing works for you. That ticket that got tossed last month over the handwriting? Can't happen; it prints. And the hour you spend transcribing at end of shift goes away entirely."},
    {"id":"narrative-gov-early-16","level":"early","profession":"publicservice","title":"The pump memo bridge","scenario":"Station 4's pump is fifteen years old and the memo requesting its replacement reads like an inventory record. The persuasive structure is a bridge: the bank we're standing on (rebuild costs climbing, two failures last winter), the far bank (the new unit's numbers), and the plank between (cost, timing, trade-in).","task":"Write the 4-sentence memo core in that where-we-are, where-we-could-be, bridge order.","tips":["Where we are: $19K in rebuilds over two years and two winter failures — the trend, not just the age.","Where we could be: one sentence, concrete — a unit under warranty through 2031.","The bridge makes it real: replacement window in Q1, trade-in offsets 15%, order by November to hold the price."],"focus":["structure","impact"],"placeholder":"Station 4's pump has cost $19,000 in rebuilds over two years and failed twice last winter, both times in freezing weather. Replacement puts a unit under full warranty through 2031 in the bay instead."},
    {"id":"narrative-gov-early-17","level":"early","profession":"publicservice","title":"Ninety seconds at the microphone","scenario":"The 30 km/h school-zone proposal is at public meeting and you have ninety seconds at the mic to support it with the collision review you wrote. Ninety seconds fits one story, one number, and one ask — not the full review. Choose them.","task":"Write the 90-second statement: the story, the number, the ask.","tips":["The story: the near-miss at Norfolk and 3rd in September, told in three sentences without embellishment.","The number that pairs with it: survival odds at 30 versus 50 — one contrast, not a table.","The ask closes it in one sentence: adopt the zone before school opens in September."],"focus":["audience","concision"]},
    {"id":"narrative-gov-early-18","level":"early","profession":"publicservice","title":"The alley door","scenario":"The same convenience store has been burgled three times through the same unlocked alley door, and the owner keeps buying camera upgrades instead. You're back after break-in three. He needs to hear the pattern he can't see from inside it — and the eighty-dollar fix that outperforms his cameras.","task":"Write the 3-sentence version: the pattern, the comparison, the specific fix.","tips":["Lay out the pattern like a story told back to him: three entries, same door, cameras filmed all three.","The comparison does the persuading: the cameras recorded the losses; a deadbolt would have prevented them.","Name the exact fix and its price — a specific eighty-dollar ask beats general security advice."],"focus":["impact","audience"],"placeholder":"All three break-ins came through the same alley door, and all three are on your cameras — which means the cameras are working and the door is the problem. An $80 deadbolt would have stopped every one of them."},
    {"id":"narrative-gov-early-19","level":"early","profession":"publicservice","title":"The recommendation buried on page two","scenario":"Your memo proposing consolidated evening counter hours spends six paragraphs on history before the recommendation appears. Decision-makers read the first paragraph and skim the rest — your structure has hidden your argument. Rebuild it: change first, two strongest reasons, history last.","task":"Rewrite the opening 3 sentences in that order.","tips":["The recommendation is the headline, not the conclusion — persuasion structure is BLUF structure.","Pick your two strongest reasons and spend one sentence each; the other four go to an appendix.","History earns a place only where it answers 'why now' — usually one clause."],"focus":["structure","concision"],"placeholder":"I recommend consolidating evening counter hours into Tuesday and Thursday, 4 to 8. Those two evenings carry 81% of our after-4 traffic, and consolidation frees eleven staff-hours a week for the backlog."},
    {"id":"narrative-gov-early-20","level":"early","profession":"publicservice","title":"The story they already believe","scenario":"The satellite clinic is moving into the main health centre, and the neighbourhood believes it's a cost-cutting closure — that story is already running ahead of yours. A notice that ignores it loses. Yours has to name their belief, meet it honestly, then tell the real story.","task":"Write the notice's first three sentences: their story named, the honest answer, the actual change.","tips":["Name the fear in their words — 'this looks like a closure' — or it stays louder than anything you write.","Meet it with the checkable fact: every service continues, same staff, eight blocks away.","Concede what's truly lost — the shorter walk — because pretending nothing is lost forfeits the rest."],"focus":["audience","structure"],"placeholder":"Many of you have heard the Oak Street clinic is closing — and we owe you a straight answer. Every service and every staff member is moving eight blocks to the Grandview centre; nothing is being cut. What you do lose is the shorter walk, and we're adding a shuttle to meet that."},
    {"id":"narrative-gov-early-21","level":"early","profession":"publicservice","title":"After the near miss","scenario":"Two weeks after the chainsaw near-miss, half the crew has already slid back to working without chaps. You get five minutes at the toolbox talk. Reciting the policy re-loses the room. The persuasive version puts them back inside that Tuesday morning, then makes the ask small and social.","task":"Say the 3-4 sentence toolbox talk that makes the near miss do the persuading.","tips":["Retell the moment with its real details — the worn guard, the two-second kickback, how close it came — not the incident-report version.","The stake is Tuesday morning, not policy: same saw, same crew, four centimetres difference.","Make the norm social: chaps go on when the saw comes out, same as ear protection — nobody thinks twice about those."],"focus":["impact","audience"]},
    {"id":"narrative-gov-early-22","level":"early","profession":"publicservice","title":"The sentence under the chart","scenario":"Your response-time chart goes to the council packet, and charts without captions get the reading the viewer prefers. The data: east-district times have climbed 90 seconds in two years while call volume rose 30% with no added crew. You get one caption sentence to make the chart mean something.","task":"Write the single caption sentence that turns the chart into the decision it supports.","tips":["A caption is the insight, not the axes: say what happened and what drives it.","Pair the two trends in one sentence so the cause can't be unseen.","Point at the decision without begging: what one more crew restores."],"focus":["concision","impact"],"placeholder":"East-district response times have climbed 90 seconds in two years as call volume rose 30% against an unchanged crew count — one added unit returns times to the four-minute standard."},
    {"id":"narrative-gov-early-23","level":"early","profession":"publicservice","title":"The price of doing nothing","scenario":"Your permit-system replacement pitch lists what the new system does. The committee's unspoken alternative is always 'do nothing — it's free'. Except it isn't: 200 staff-hours a month of manual workarounds, and an annual vendor fee rising 12% a year on the dying system. Cost the status quo.","task":"Write a 3-sentence passage that prices 'do nothing' before presenting the new system.","tips":["'Do nothing' is your real competitor — beat it explicitly or lose to it silently.","Convert workarounds to money: 200 hours a month at loaded cost is the number the committee hears.","Then land the comparison: doing nothing costs more within three years, before counting a single outage."],"focus":["impact","precision"],"placeholder":"Keeping the current system is not free: manual workarounds consume 200 staff-hours a month, and the legacy vendor fee is rising 12% a year. On those two lines alone, doing nothing costs more than replacement within three years."},
    {"id":"narrative-gov-early-24","level":"early","profession":"publicservice","title":"Winning the room back","scenario":"Twenty minutes into the detour meeting, the room has turned — arms crossed, someone's phone recording, the last speaker got applause for calling the plan 'a stitch-up'. Your case is sound, but sound cases don't land on hostile rooms. The next two sentences have to acknowledge before they argue.","task":"Say the two sentences: the genuine acknowledgment of their loss, then the turn.","tips":["Acknowledge the specific loss, not the feeling: eight months of trucks past their homes is worth naming exactly.","No 'but' straight after the acknowledgment — let it stand for a full stop first.","The turn earns attention rather than demanding it: 'here's the one thing I'd want to know in your seat.'"],"focus":["audience","impact"]},
    {"id":"narrative-gov-early-25","level":"early","profession":"publicservice","title":"The ask they can do today","scenario":"Your fire-hall open house speech about smoke-alarm batteries ends with 'so please, everyone, stay fire safe out there' — an ending that asks for nothing and gets it. Persuasion finishes with an action the audience can take today, sized so small that not doing it feels sillier than doing it.","task":"Write the closing two sentences: the specific ask, and the tonight-sized version of it.","tips":["'Stay safe' is a mood; 'test your alarm tonight' is an instruction.","Shrink it to one motion: press the button on the way to bed — ten seconds.","Add the fallback that catches the rest: no beep, and this station gives you a battery free, any day."],"focus":["clarity","impact"],"placeholder":"Tonight, on your way to bed, press the test button on your hallway alarm — ten seconds, one thumb. If you don't hear the beep, come by this station any day and the battery is free."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-gov-early-01","level":"early","profession":"publicservice","title":"The denial, said first","scenario":"You're calling an applicant about her rent-assistance application. It's denied — her income sits $40 a month over the threshold. Your draft script warms up with two minutes of process talk before the verdict, which means she'll spend those two minutes hoping.","task":"Write the call script: the decision in the first sentence, the reason, then the path.","tips":["Every sentence before the verdict is false hope — lead with it, gently but first.","The precise reason is respect: $40 a month over, not 'you didn't qualify'.","The path is real here: the threshold resets in April, and the utility program has a higher cutoff."],"focus":["clarity","audience"],"placeholder":"I'm calling about your rent-assistance application, and I'm sorry — it's been denied. Your income is $40 a month over the program threshold."},
    {"id":"hard-gov-early-02","level":"early","profession":"publicservice","title":"The tow that's already hooked","scenario":"The owner is running toward you as the tow truck lifts his car from the accessible zone. The ticket's written and the hook is on — there's no discretion left to offer. What you owe him is the situation stated plainly, and exactly what he does next to get his car back.","task":"Say the 2-3 sentences: what's happening, why, and the retrieval steps.","tips":["Don't pretend there's a negotiation — false hope now doubles the anger in a minute.","One sentence of why, factual: accessible zone, no permit displayed.","Spend most of your words on his next steps: the lot address, the hours, what it costs, what to bring."],"focus":["clarity","impact"]},
    {"id":"hard-gov-early-03","level":"early","profession":"publicservice","title":"Telling the sergeant you lost the notes","scenario":"Your notebook page covering Tuesday's traffic stop — now subject to a complaint — is gone. You've searched twice; it's gone. Every hour you sit on this makes it worse, and the version where the sergeant finds out from someone else is the worst of all.","task":"Write what you'd say: the loss, plainly, then scope and what you've done.","tips":["Headline first: 'I've lost my notes from the Tuesday stop.' No run-up.","Scope it precisely — which pages exist, what the CAD and camera still cover.","Bring your actions, not your excuses: searched the car and locker, drafted a statement from memory today, dated."],"focus":["clarity","impact"],"placeholder":"Sergeant, I need to flag a problem straight away: my notebook pages from Tuesday's traffic stop are missing. I've searched the cruiser and my locker twice."},
    {"id":"hard-gov-early-04","level":"early","profession":"publicservice","title":"The notification, without euphemism","scenario":"You and your partner are at the door to tell a woman her husband has died in a workplace accident. The instinct under this weight is to soften into vagueness — 'there's been an incident', 'he didn't make it' — sentences that make her ask the question you came to answer.","task":"Say the notification: identity confirmed, the plain sentence, then presence.","tips":["Confirm you have the right person first — this news to a wrong address is catastrophic.","Use the plain words: 'I'm very sorry — your husband, Daniel, has died.' Euphemism creates a cruel minute of hope.","Then stop talking. Your next job is to stay, not to fill the silence."],"focus":["audience","clarity"]},
    {"id":"hard-gov-early-05","level":"early","profession":"publicservice","title":"Failing the kitchen you like","scenario":"The family diner you've inspected for three years — good people, always try hard — fails today: cooler at 9°C for what looks like two days, and re-inspection before they can serve again. Your fondness is pulling the message toward mush, and mush would leave them open and at risk.","task":"Write what you'd tell the owner: the result, the two facts, the fastest path back.","tips":["Liking them is exactly why to be clear — vagueness leaves them legally exposed and guessing.","The result first: 'You've failed today's inspection and can't serve until re-inspection.'","Fastest path back is the kindness: fix the cooler today, call this number, I can be back tomorrow morning."],"focus":["clarity","audience"],"placeholder":"Maria, I have to fail you today, and I want to be straight about it because you deserve straight. The cooler's been at 9 degrees for what looks like two days, and you can't serve until I re-inspect."},
    {"id":"hard-gov-early-06","level":"early","profession":"publicservice","title":"No to the shift swap","scenario":"A colleague who covered for you in March asks you to take her Friday night shift. You can't — it's your daughter's play, booked for months. Your draft answer is a hedge-maze of 'let me see' that she'll reasonably read as a probable yes, and Friday will find her uncovered.","task":"Write the 2-sentence answer: the clean no with its reason, and the alternative you'll help with.","tips":["A slow maybe that becomes no is worse than a fast no — it costs her the time to find someone else.","One honest reason, no inflation: my daughter's play, I can't move it.","Offer what you can actually do: ask the group chat with her, or take her Sunday instead."],"focus":["concision","clarity"],"placeholder":"I can't take Friday — it's my daughter's school play and that one's immovable. I can post it to the group chat right now with you, and I'll take your Sunday if that helps square it."},
    {"id":"hard-gov-early-07","level":"early","profession":"publicservice","title":"The unsafe-structure order","scenario":"You've assessed the fire-damaged porch and it's coming down — the order is signed and the homeowner is standing next to you, hoping. The order is not negotiable; the timeline and the process have some give. The kind version separates those clearly instead of blurring them.","task":"Write what you'd say: the order plainly, the why in one sentence, then where the give is.","tips":["Lead with the unchangeable: the porch has to come down — the order is issued.","One sentence of why, physical: the main beam is burned through and it can collapse without warning.","Then the give: 30 days to arrange it, your own contractor, and rebuild permits are fast-tracked after fire."],"focus":["clarity","impact"],"placeholder":"I have to give you the hard news first: the porch can't be saved — I'm issuing a demolition order today. The main support beam is burned through, and it could come down without any warning."},
    {"id":"hard-gov-early-08","level":"early","profession":"publicservice","title":"Feedback on the unusable report","scenario":"A newer colleague's incident report crossed your desk for review and it can't go up: no times, hearsay presented as observation, and the actual incident appears in paragraph four. 'It's a bit rough, maybe tighten it up?' would be easier to say and useless to receive.","task":"Write the feedback: the three specific problems, each with its fix, nothing about him.","tips":["Vague feedback is a kindness to you, not to him — specific is what he can act on.","Three items, each as problem-plus-fix: no times → pull them from CAD before writing.","Keep every sentence about the report, none about the person — and say what the report got right, once, honestly."],"focus":["precision","audience"],"placeholder":"Three fixes before this can go up. First: the incident itself needs to open the report — right now it arrives in paragraph four."},
    {"id":"hard-gov-early-09","level":"early","profession":"publicservice","title":"The fee that isn't coming back","scenario":"An applicant withdrew his rezoning application and wants his $600 application fee back. The bylaw is unambiguous: application fees are non-refundable once review begins, and review began three weeks ago. Your draft reply spends four sentences almost saying so.","task":"Rewrite the reply: the no in the first sentence, the reason, and the one real option.","tips":["A slow no reads as a maybe and generates the appeal you're trying to avoid.","Ground it in the rule and the fact: review began March 3rd — the fee paid for work that happened.","The real option, if any: the fee credits toward a resubmission within 12 months. Offer nothing that isn't real."],"focus":["clarity","audience"],"placeholder":"I'm sorry to say the $600 application fee can't be refunded. Review of your file began on March 3rd, and under the bylaw the fee covers that review work whether or not the application proceeds."},
    {"id":"hard-gov-early-10","level":"early","profession":"publicservice","title":"The exercise failed its objective","scenario":"You ran the evacuation drill for your section and it failed: the assembly point took 14 minutes against an 8-minute standard, and two staff never heard the alarm. The report tempts you toward 'valuable lessons were learned'. Command needs the failure stated as a failure, with causes.","task":"Write the report's first three sentences: the result against standard, the two causes, next test date.","tips":["'Did not meet standard' is the finding — say it in sentence one with both numbers.","Causes as facts, not blame: the stairwell bottleneck, and the dead PA speaker on the east wing.","Credibility comes from the retest commitment: fixes by the 15th, drill rerun on the 22nd."],"focus":["clarity","structure"],"placeholder":"The evacuation drill did not meet standard: full assembly took 14 minutes against the 8-minute requirement, and two staff never heard the alarm."},
    {"id":"hard-gov-early-11","level":"early","profession":"publicservice","title":"The volunteer conversation","scenario":"A volunteer firefighter — well-liked, five years in — has missed 70% of calls this year and failed to recertify on breathing apparatus. The roster rules are clear and it's your job to tell him he's coming off active status. He'll hear it as the station rejecting him.","task":"Say the conversation opener: the decision, the specific grounds, and what remains open.","tips":["The decision first, in plain words — letting him discover it mid-conversation is crueler.","Grounds are the two facts, not his character: the attendance number and the lapsed certification.","What remains open must be genuine: recertify and rebuild attendance, and reinstatement is the normal path."],"focus":["audience","clarity"]},
    {"id":"hard-gov-early-12","level":"early","profession":"publicservice","title":"The estimate you blew","scenario":"You told your manager the fleet's brake repairs would run about $4,000. The final invoices total $7,300 — you missed that three vehicles needed rotors, not just pads. He'll see the invoices Thursday. The message you send today decides whether this is a mistake or a trust problem.","task":"Write the message: the number first, the miss explained in one sentence, the fix to your process.","tips":["Lead with the real number and the gap — he must not learn it from the invoice.","Own the cause specifically: I quoted from the inspection sheet without pulling the wheels.","The process fix is what rebuilds trust: estimates over $2K now get a teardown check first."],"focus":["impact","precision"],"placeholder":"Heads-up before Thursday's invoices reach you: the brake work came in at $7,300, not the $4,000 I estimated. I quoted from the inspection sheets without pulling wheels, and three vehicles needed rotors, not just pads."},
    {"id":"hard-gov-early-13","level":"early","profession":"publicservice","title":"Denying the parade","scenario":"The heritage-day parade has run for thirty years, and this year's application fails the new provincial traffic-management rules — no certified marshal plan. You must deny it as submitted. The organizers will hear 'the city killed the parade' unless your letter makes the fixable part unmissable.","task":"Write the letter's first three sentences: the denial, the single failing item, the fix and its deadline.","tips":["Deny the application, not the parade — that distinction is the whole letter.","Name the one missing piece precisely: a certified traffic-marshal plan, and the two firms that produce them.","Deadline math is the kindness: resubmitted by May 1, approved in time for the June date."],"focus":["clarity","audience"],"placeholder":"As submitted, this year's parade application must be denied — but the parade itself doesn't have to be. The application is missing one required item: a certified traffic-marshal plan, which the new provincial rules make mandatory."},
    {"id":"hard-gov-early-14","level":"early","profession":"publicservice","title":"The service cut, unspun","scenario":"Saturday counter hours end next month — a budget decision, decided above you. The draft public notice buries the cut under three sentences about 'exciting improvements to our service model'. Residents will find the cut anyway, and the spin will be what they remember.","task":"Rewrite the notice: the cut first and plain, the reason honestly, the alternatives that exist.","tips":["Say the thing: Saturday counter service ends March 1. Cushioning it with 'exciting' insults the reader.","One honest reason beats a paragraph of framing — budget reduction, stated as itself.","Alternatives only if real: online for these six services, and Thursday hours extended to 7."],"focus":["clarity","audience"],"placeholder":"Saturday counter service ends March 1. This is a budget decision, and we'd rather tell you plainly than dress it up."},
    {"id":"hard-gov-early-15","level":"early","profession":"publicservice","title":"'Why am I always plowed last?'","scenario":"A resident calls, furious, asking why her cul-de-sac is always the last plowed street in town. The true answer is the priority system — arterials, bus routes, and school corridors first, and her street is a dead-end serving nine houses. That truth can be told with respect or with a shrug.","task":"Write the answer: the honest priority order, her street's place in it, and the real timing.","tips":["The system is defensible — explain it rather than hiding behind it.","Tell her where she actually sits: last tier, plowed within 36 hours of snow-end, and here's the map link.","Don't apologize for the priority order; do give her the one thing that helps — the windrow rule for her driveway."],"focus":["audience","clarity"],"placeholder":"I'll give you the straight answer: the plows run a strict order — arterials and emergency routes, bus routes, school corridors, then residential, and dead-end streets come last within residential. Your street is nine houses on a cul-de-sac, so it lands at the end of that list."},
    {"id":"hard-gov-early-16","level":"early","profession":"publicservice","title":"Correcting the office's mistake","scenario":"A colleague told a food-truck applicant last week that his location was pre-approved. It wasn't — it's inside a school-adjacent exclusion zone, and he's already ordered signage with the address on it. You're the one calling to unwind it, and the error is the office's, not his.","task":"Write the call script: the correction, the ownership, and what the office will do about his costs.","tips":["Lead with the correction and the ownership in the same breath: we told you wrong.","Never blame the colleague by name to the applicant — 'we' is the only honest pronoun for an office error.","Concrete redress before he asks: the two nearest compliant locations, and the claim form for the signage."],"focus":["clarity","impact"],"placeholder":"Mr. Tran, I'm calling to correct something we got wrong, and I want to say up front the error is ours, not yours. The Lakeview location you were told was approved sits inside a school exclusion zone, and we cannot license it."},
    {"id":"hard-gov-early-17","level":"early","profession":"publicservice","title":"The tree is coming down","scenario":"The sixty-year-old maple in front of a resident's house — the one in her family photos — has advanced trunk rot and is over the sidewalk and her roofline. Removal is scheduled and not reversible. She's asked to 'discuss options', and the truthful answer is that there aren't any.","task":"Write your response: the decision plainly, the physical reason, and what happens after.","tips":["Do not take the meeting pretending options exist — that's a second injury later.","The reason must be physical and checkable: the resistograph readings, offered to show her.","After matters here: removal date, stump grinding, and the replacement planting she can choose the species for."],"focus":["clarity","audience"],"placeholder":"Mrs. Aldi, I owe you a direct answer: the maple is coming down on the 9th, and that decision can't be reversed. The testing shows rot through more than half the trunk, and it stands over your roof and a public sidewalk."},
    {"id":"hard-gov-early-18","level":"early","profession":"publicservice","title":"The glove conversation","scenario":"Your regular partner has started skipping gloves on 'quick' patient contacts — twice this week. It's a habit that ends careers and worse. This is a private word between partners, not a report — yet — and it has to be specific enough that he can't wave it off as nagging.","task":"Say the 2-3 sentences: the specific instances, the stake, and the line you'll hold.","tips":["Name the two instances — 'the lift assist Tuesday, the nosebleed today' — vague concern gets vague dismissal.","The stake is his, made concrete: one hep-C contact is the rest of his career.","The line, stated as fact and without threat: next time I stop the contact until you're gloved."],"focus":["audience","precision"]},
    {"id":"hard-gov-early-19","level":"early","profession":"publicservice","title":"Escalating a colleague's error","scenario":"Reviewing yesterday's files, you found a colleague approved a burn permit inside the current fire ban — a clear error with live risk. You have to send it up. The report has to be factual and complete without becoming either a prosecution or a burial.","task":"Write the escalation: the error and its risk first, the facts, no verdicts on the person.","tips":["The live risk is the headline — a burn permit active during a ban — because someone must act on it today.","Facts only: permit number, date, the ban order it conflicts with. No 'carelessly', no 'as usual'.","Include the immediate fix you took or propose: permit suspended pending review, holder notified."],"focus":["precision","clarity"],"placeholder":"Flagging an error that needs action today: burn permit 4471, issued yesterday, conflicts with the fire ban in effect since June 1. The permit holder has not yet been notified."},
    {"id":"hard-gov-early-20","level":"early","profession":"publicservice","title":"The frequent caller","scenario":"The same man has called 911 eleven times this month — loneliness and minor ailments, never emergencies. Today you're the paramedic sitting in his kitchen again, and someone has to tell him the truth: this line can't be his company, and there's a number that can be. Shame will make him hide instead of dial differently.","task":"Say the 3-sentence version: the plain fact, why it matters, and the right door held open.","tips":["State the pattern without contempt: eleven calls, none emergencies — he already knows, and pretending otherwise is what insults him.","Why it matters, concretely: while a crew sits here, a chest-pain call waits longer.","The redirect must be a real door: the community paramedic program, and you'll make the first referral call yourself."],"focus":["audience","impact"]},
    {"id":"hard-gov-early-21","level":"early","profession":"publicservice","title":"The overtime is cancelled","scenario":"Budget word came down at noon: the weekend overtime your crew was counting on — some of them financially — is cancelled. The temptation is to let it trickle out through the schedule change. Every hour of delay is an hour someone plans around money that isn't coming.","task":"Write the crew message: the cancellation first, the reason straight, what's still true.","tips":["The people affected worst are why you send it now — some have already spent that money in their heads.","Reason without editorializing: a budget directive from the department, effective immediately.","What's still true helps them re-plan: regular hours unchanged, and the statutory-holiday premium next month stands."],"focus":["clarity","concision"],"placeholder":"Hard news and I won't dress it up: the weekend overtime is cancelled, effective immediately, on a budget directive from the department. Regular schedules are unchanged."},
    {"id":"hard-gov-early-22","level":"early","profession":"publicservice","title":"'Close your shop now'","scenario":"A gas leak two buildings down means this block evacuates immediately — and the barber mid-haircut is arguing for ten more minutes. There is no ten minutes, and this conversation must end in seconds with him moving. Firm, brief, and final — without theatrics that spike panic in the shop.","task":"Say the 2-sentence version that ends the discussion and starts him moving.","tips":["No negotiation surface: 'now' with a reason, not a request with a rationale.","Give the moving instruction, not just the leaving one: out the front, left to the community centre.","Level tone, short words — urgency is in the content, not the volume."],"focus":["impact","concision"]},
    {"id":"hard-gov-early-23","level":"early","profession":"publicservice","title":"The appeal with no chance","scenario":"An applicant wants to appeal her permit refusal, and she's asking you — the clerk who knows the file — whether it's worth the $150 appeal fee. It isn't: the refusal is on a hard setback rule with no variance history, and every similar appeal in memory has failed. False hope here costs her real money.","task":"Write the honest answer: your read, its basis, and what you'd do in her place.","tips":["You can't decide for her, but you can be honest about the pattern — that's not overstepping, it's the service.","Basis, not vibes: the rule allows no discretion, and similar appeals have failed consistently.","Give the alternative that can work: the redesign at 1.5 metres, which needs no appeal at all."],"focus":["audience","precision"],"placeholder":"I'll be honest with you, because the appeal costs real money: this refusal is on a fixed setback rule where the panel has no discretion, and I can't recall an appeal like it succeeding. If it were my file, I'd put the $150 toward redrawing the plan at 1.5 metres instead — that version passes without any appeal."},
    {"id":"hard-gov-early-24","level":"early","profession":"publicservice","title":"The failed sample, sent up plain","scenario":"The weekly water sample from the east reservoir failed — coliform detected, retest underway, notification rules may trigger within 24 hours. Your email to the manager wants to soften itself ('slightly anomalous result'). This is the one message that must be undecorated.","task":"Write the email: result, meaning, actions underway, decision point — four sentences.","tips":["'Failed — coliform detected' is the subject line and the first sentence. Softening language delays response.","Meaning next, calibrated: what it may indicate and what the retest resolves.","End at the decision point with its clock: if the retest confirms by 14:00 tomorrow, public notification rules apply."],"focus":["clarity","structure"],"placeholder":"The east reservoir weekly sample failed: coliform detected. A confirmation retest is already running, with results expected by 14:00 tomorrow."},
    {"id":"hard-gov-early-25","level":"early","profession":"publicservice","title":"No to your own supervisor","scenario":"Your supervisor, jammed by an audit deadline, asks you to date-stamp yesterday's date on applications that arrived this morning — 'they were basically here'. It's small, it's understandable, and it's falsifying a record. The no has to be immediate, clean, and survivable for both of you.","task":"Write what you'd say: the refusal, the reason in one sentence, and the legitimate help you can offer.","tips":["Refuse the act, not the person: 'I can't stamp them with yesterday's date' — no lecture attached.","One-sentence reason, factual: the stamp certifies arrival date, and these arrived today.","Offer the real help in the same breath: a note documenting the courier delay, which the auditors accept."],"focus":["clarity","impact"],"placeholder":"I can't put yesterday's stamp on them — the stamp certifies when they actually arrived, and these came in this morning. What I can do right now is draft the courier-delay memo; the auditors take those."}
  ],
  "putting-it-together": [
    {"id":"together-gov-early-01","level":"early","profession":"publicservice","title":"The complete incident report","scenario":"A cyclist and a delivery van collided at Weller and 4th; minor injuries, cyclist transported, driver cooperative, one independent witness, road reopened by 08:50. Everything you've practiced converges: lead with the event, keep chronology clean, times exact, hearsay labeled.","task":"Write the full report body — 5-7 sentences — with BLUF, chronology, and labeled sources.","tips":["First sentence carries event, location, time, outcome — a supervisor should be able to stop there.","Then chronology forward from your arrival, times from CAD.","Your observations in your voice; the witness's account in hers, attributed by name."],"focus":["structure","precision"],"placeholder":"At 08:12 a delivery van and a cyclist collided at Weller and 4th; the cyclist was transported with minor injuries and the intersection reopened at 08:50."},
    {"id":"together-gov-early-02","level":"early","profession":"publicservice","title":"One break, three channels","scenario":"A water main has let go on Fenwick Avenue: eight houses without water, repair crew ETA two hours, boil advisory likely after restoration. Three messages leave your hands in the next ten minutes — a radio line to dispatch, three sentences to your supervisor, and a door notice for the eight houses.","task":"Write all three, each fitted to its reader and channel.","tips":["Dispatch gets facts for the board: location, scope, crew ETA, traffic impact.","Supervisor gets the decision-shaped version: situation, what you've set in motion, the one thing you need.","Residents get their stake first: water off now, back by roughly when, boil it after — in door-hanger words."],"focus":["audience","structure"],"placeholder":"Dispatch: main break at 300-block Fenwick, eight houses out, crew ETA two hours, single-lane traffic past the site."},
    {"id":"together-gov-early-03","level":"early","profession":"publicservice","title":"The handover that protects the night","scenario":"End of your counter shift, and the handover note has to work while you're unreachable: one live promise (a callback to a resident about a disputed fine by 15:00 tomorrow), one brewing issue (the card terminal acting up), and the routine state of the queue. Order and precision decide whether tomorrow goes smoothly.","task":"Write the full handover note: live item first, then the watch item, then routine — with times and file numbers.","tips":["The reader is tomorrow-you's replacement: assume no context and no chance to phone you.","Live item gets file number, name, promised time, and where the notes live.","Separate 'must do' from 'watch' from 'FYI' with actual headers — structure is the courtesy."],"focus":["structure","concision"],"placeholder":"MUST DO — Mr. Okafor (file P-8841) was promised a callback on his disputed fine by 15:00; full notes in the file, decision memo attached."},
    {"id":"together-gov-early-04","level":"early","profession":"publicservice","title":"Five minutes at the community centre","scenario":"Last night's apartment fire displaced twelve families, and you're giving the morning briefing at the community centre: what happened, what's known and not known, what displaced residents do next, when the next update comes. Then the first question from the floor will be hostile — 'why did it take so long?' — and you know the answer is defensible.","task":"Outline the 5-minute briefing in its spoken order, then the 2-sentence answer to the hostile question.","tips":["Structure the briefing as: what happened, what we know / don't know, what you should do, next update time.","Never guess in the unknowns section — name when each unknown resolves instead.","For the hostile question: answer it directly with the timeline fact before any context."],"focus":["audience","structure"]},
    {"id":"together-gov-early-05","level":"early","profession":"publicservice","title":"The escalation with everything","scenario":"The permit backlog has crossed the line you flagged a month ago: 220 files, statutory deadlines now missed on 9 of them, and legal exposure starting to accrue. Your escalation email to the branch director has one shot to be complete: headline, evidence, ask, deadline, and what you'll do if you hear nothing.","task":"Write the full email — 5 sentences — with all five elements in that order.","tips":["The headline is the missed statutory deadlines, not the backlog — lead with the part that has legal teeth.","Evidence in one dense sentence: the counts, the trend, the date you first flagged it.","The default action makes it real: without direction by Friday, I start deadline-triage per the contingency memo."],"focus":["structure","impact"],"placeholder":"We have now missed statutory deadlines on 9 permit files, with 14 more crossing that line within two weeks — this needs a decision this week."},
    {"id":"together-gov-early-06","level":"early","profession":"publicservice","title":"Edit your own draft","scenario":"Your draft memo about the equipment cage runs 300 words: the recommendation hides in the last paragraph, 'I think' and 'possibly' appear nine times between them, and one sentence presents your hunch about the missing gear as fact. Before it goes to the station chief, run the full edit pass on it.","task":"Write the repaired opening 3 sentences: conclusion moved up, hedges cut, inference labeled.","tips":["Find the sentence you wrote last — it's usually the real first sentence.","Keep one honest uncertainty if it's real; delete the eight reflexive ones.","Anything you didn't see gets an 'appears' or 'in my assessment' — precision about knowledge is part of the edit."],"focus":["concision","clarity"],"placeholder":"I recommend we re-key the equipment cage and log all access for thirty days. Two breathing-apparatus masks are unaccounted for since the 12th; in my assessment the cage's shared key is the weak point."},
    {"id":"together-gov-early-07","level":"early","profession":"publicservice","title":"The memo for the file","scenario":"At the counter today you accepted a late-filed appeal because the courier receipt showed it arrived in the building on time — a judgment call, inside your delegation, but the kind that gets questioned a year later by someone who wasn't there. Write it down as if for that stranger.","task":"Write the file memo: the decision, the facts it rested on, the authority, in 3-4 sentences.","tips":["Write for a reader with no context and possibly an agenda — a year from now, this memo is the only witness.","Decision first, then the two facts that drove it, then the delegation clause you acted under.","Date-stamp the facts: the receipt time, the deadline, who you consulted if anyone."],"focus":["precision","structure"],"placeholder":"On June 12 I accepted appeal file A-3302 despite its arrival at the counter one day past deadline. The courier receipt shows the package reached the building mailroom June 10 at 14:05 — inside the deadline."},
    {"id":"together-gov-early-08","level":"early","profession":"publicservice","title":"Radio words, report words","scenario":"This morning's pursuit-and-stop plays back in two registers: the radio traffic ('northbound Grove, sixty, one occupant...') and tonight's report, where clipped fragments must become complete, precise, first-person sentences without gaining or losing a single fact. Most people let the registers bleed. Don't.","task":"Write both: the 2-line radio version, then the same events as 3 report sentences.","tips":["Radio: fragments, no articles, present tense — the channel's grammar exists for a reason.","Report: complete past-tense sentences, exact times, full words — 'the vehicle' not 'unit'.","Check that both carry identical facts — register changes the clothing, never the content."],"focus":["audience","precision"],"placeholder":"Radio: 'Pursuit northbound Grove from 5th, grey sedan, speeds sixty, one occupant.' Report: At 07:42 I initiated pursuit of a grey sedan northbound on Grove Street from 5th Avenue."},
    {"id":"together-gov-early-09","level":"early","profession":"publicservice","title":"Three minutes, whole crew, no drift","scenario":"You're running the morning briefing solo: the trench job on Mill Road with its shoring requirement, a heat advisory for the afternoon, and the new fueling-log procedure. Three minutes, six people, tasks assigned by name, and one comprehension check — everything the modules taught, live.","task":"Deliver the briefing: signposted open, item-task-name for each, and the closing check.","tips":["Open with the map — 'three items' — and honor it; drift is what briefings die of.","Safety item gets a named behavior, not a mood: water breaks every 45 minutes, on the timer, non-optional.","Close with a real check: 'Dev, what's the shoring depth trigger?' beats 'everyone clear?'"],"focus":["structure","concision"]},
    {"id":"together-gov-early-10","level":"early","profession":"publicservice","title":"The complaint answered whole","scenario":"A resident's written complaint says your crew left her street 'a mud pit' and ignored her when she asked about it. Partly true: the restoration topsoil was delayed a week, and the crew member she approached was new and brushed her off. The reply has to acknowledge, state facts, own the miss, and commit — in four sentences.","task":"Write the complete reply.","tips":["Acknowledge the specific experience before any facts — she was brushed off, and that comes first.","Facts without defensiveness: topsoil delayed to the 18th, and here's the restoration standard her street will meet.","One commitment with a date and a name — hers to hold you to."],"focus":["audience","structure"],"placeholder":"You're right on both counts, and I'm sorry: the street should not have been left unrestored this long, and you should not have been waved off when you asked about it."},
    {"id":"together-gov-early-11","level":"early","profession":"publicservice","title":"The grant paragraph","scenario":"The regional grant application allows one 100-word paragraph to justify replacing the station's extrication tools. Everything must compress: the need (current tools can't cut modern high-strength car frames), the evidence (three incidents this year), the ask, and the impact — with zero words wasted.","task":"Write the paragraph: need, evidence, ask, impact, in exactly that order, under 100 words.","tips":["Every sentence carries one element and earns its length — this is concision under a hard cap.","The evidence sentence does the persuading: three incidents where cutting took over 20 minutes.","End on impact in human units: minutes off extrication time is the whole point of the money."],"focus":["impact","concision"],"placeholder":"Our extrication cutters, purchased in 2012, cannot cut the high-strength steel now standard in vehicle frames. Three times this year, extrications exceeded twenty minutes because the tools could not make the cut."},
    {"id":"together-gov-early-12","level":"early","profession":"publicservice","title":"From notebook to statement","scenario":"Court in three weeks, and your notebook from the February assault call has to become a witness statement: fragments, times, a sketch, and two quotes. The statement needs everything integrated — clean chronology, exact times, observations only in your voice, the quotes attributed exactly.","task":"Write the statement's first 4 sentences from raw notes: arrival, scene, observation, first action.","tips":["The statement is chronology with a spine: each sentence advances time.","Anything not in the notebook doesn't go in the statement — memory has a cutoff date and counsel knows it.","Quotes go in quotation marks with the speaker named; paraphrase is where statements die."],"focus":["precision","structure"],"placeholder":"I arrived at 22 Dundalk Street at 21:47 in response to a radio call reporting an assault in progress. The front door stood open and I could hear raised voices from the rear of the house."},
    {"id":"together-gov-early-13","level":"early","profession":"publicservice","title":"The outage chain, all three links","scenario":"The benefits system just went down province-wide, mid-morning, no ETA. Three messages, three audiences, ten minutes: one line up to your manager, one line to the counter team, and the sign for the door. Each reader needs a different first word.","task":"Write all three messages, each one or two lines, each audience-first.","tips":["Manager: scope and what you've done — 'all stations down, ticket filed, paper intake running'.","Team: instructions — what to offer, what to log, when the next word comes.","Public: what they can still do today, biggest and first; the apology is one word, not the headline."],"focus":["audience","concision"],"placeholder":"To manager: Benefits system down at all stations since 10:20, provincial ticket 88412 filed; we're on paper intake and I'll update you at noon."},
    {"id":"together-gov-early-14","level":"early","profession":"publicservice","title":"The end-of-rotation report","scenario":"Six months at the northern detachment ends Friday, and the rotation report you leave behind is the only version of your work that persists. It needs outcomes first, numbers behind them, one honest lesson, and the two live items your replacement inherits — in one page, structured for a reader who skims.","task":"Write the report's opening: the outcome summary sentence, two supporting numbers, the lesson, one live item.","tips":["Lead with the changed thing, not the activity: response coverage, not 'conducted patrols'.","Numbers make the outcomes portable: they'll be quoted long after the prose is forgotten.","The honest lesson is what makes the rest believable — one real one, stated without flinching."],"focus":["structure","impact"],"placeholder":"Over six months the detachment cut average response time from 22 minutes to 14 and cleared the summons backlog to zero. The single biggest factor was moving the second car to an overlap shift — a change I'd recommend making permanent."},
    {"id":"together-gov-early-15","level":"early","profession":"publicservice","title":"The board question, in sixty seconds","scenario":"Promotion board: 'Tell us about a time you handled a difficult member of the public.' You have the real story — the man who spent twenty minutes shouting about his tow before you found the actual problem, a misapplied fee, and fixed it. Sixty seconds: situation, what you did, the result, structured aloud.","task":"Give the 60-second answer: one sentence of setup, the turn, your action, the measured result.","tips":["Setup in one sentence — boards lose patience with scene-setting.","The turn is the story: the shouting was about the tow, but the problem was a $180 misapplied fee.","End with the result and its echo: fee reversed in ten minutes, and he's been civil at the counter since."],"focus":["structure","audience"]},
    {"id":"together-gov-early-16","level":"early","profession":"publicservice","title":"The whole ask in one email","scenario":"The station's only wheelchair lift has been broken nine days. You've told the property line twice by phone; now it goes in writing, complete: the headline, the impact so far (four residents turned away, one formal complaint), the deadline you need, and what happens if it passes. One email, everything on the table.","task":"Write the full email — 4-5 sentences — BLUF through fallback.","tips":["Written record changes the register: dates, prior contacts, and counts all go on the page now.","The impact is people, counted: four turned away, one complaint filed — not 'accessibility concerns'.","The fallback is a fact, not a threat: past Friday, I refer it to the accessibility compliance office as required."],"focus":["clarity","impact"],"placeholder":"The wheelchair lift at the Main Street office has now been out of service nine days, and I need a repair date by Friday. Since the 3rd we have turned away four residents who could not reach the second-floor counter, and one has filed a formal complaint."},
    {"id":"together-gov-early-17","level":"early","profession":"publicservice","title":"The hard incident, reported whole","scenario":"During last night's arrest, the subject fell against a parked car and cracked its windshield — he wasn't injured, the takedown was by the book, and the car owner is upset. The report to your supervisor needs it all at once: hard headline, precise facts, your account separated from the subject's, next steps.","task":"Write the report's first 4 sentences integrating all of it.","tips":["Bad-news BLUF: the property damage and the circumstances, first sentence, no cushion.","Precision is your protection: the mechanics of the fall, in physical terms, times attached.","The subject's version goes in too, labeled as his statement — completeness is credibility on hard files."],"focus":["clarity","precision"],"placeholder":"During the 23:15 arrest on Corey Street, the subject fell against a parked vehicle during the takedown, cracking its windshield; he was not injured and the takedown followed procedure."},
    {"id":"together-gov-early-18","level":"early","profession":"publicservice","title":"The deadline notice that works","scenario":"Dog licence renewals close March 31, after which the fee doubles — and every year hundreds of residents get caught because the notice buried the date. This year's notice is yours: action, date, consequence, easiest path — ordered for a reader giving it four seconds on the fridge.","task":"Write the notice: four lines, biggest thing first.","tips":["Line one is the action and date: 'Renew your dog licence by March 31.' Everything else supports it.","The consequence is the motivator — 'fee doubles April 1' — stated as fact, not scolding.","The easiest path gets a full line: online in five minutes, and the exact web address."],"focus":["audience","clarity"],"placeholder":"Renew your dog licence by March 31. On April 1 the fee doubles — $25 becomes $50."},
    {"id":"together-gov-early-19","level":"early","profession":"publicservice","title":"The binder page for your replacement","scenario":"You rotate off the front counter for a year on secondment, and your replacement arrives Monday with no overlap. One page has to carry them: the two live files, the three people who solve problems, the weekly rhythms, and the one trap everyone falls into. Write it like a letter to a capable stranger.","task":"Write the page's structure and first lines: live items, key contacts, rhythms, the trap.","tips":["Order by urgency of discovery: what bites in week one goes first.","Contacts with the why attached: 'Rana in IT — terminal issues, answers same hour.'","The trap earns its own header: the month-end batch run, and what happens to payments logged after 4 PM."],"focus":["structure","audience"],"placeholder":"LIVE NOW — Two files can't wait for you to settle in: the Chen appeal (A-2291, hearing the 14th, folder in the top drawer) and the disputed fine callback owed by Friday."},
    {"id":"together-gov-early-20","level":"early","profession":"publicservice","title":"Debrief in four beats","scenario":"The crew is still packing up from the two-vehicle extrication and the debrief falls to you: what happened, what went well, what didn't, what changes — four beats, five minutes, no wandering. The 'what didn't' beat is the one that takes spine: the second crew blocked the ambulance's exit path.","task":"Deliver the debrief in the four-beat structure, one to two sentences per beat.","tips":["Announce the structure first — four beats keeps a tired crew with you.","'What went well' is specific or worthless: the 90-second stabilization, named to the people who did it.","'What didn't' states the fact without a culprit: the rig placement cost us three minutes — placement, not the driver, is the subject."],"focus":["structure","concision"]},
    {"id":"together-gov-early-21","level":"early","profession":"publicservice","title":"Ending the reply-all storm","scenario":"The parking-rota thread is thirty messages deep and gaining, with four proposals and rising temperature. You have the authority to end it, and the ending is one message: the decision, the one-sentence reason, the effective date, and where remaining objections go — nothing that reopens debate.","task":"Write the thread-ending message.","tips":["Open with 'Decision:' — the word itself closes the question.","One reason, chosen because it's the one nobody disputed — not a rebuttal of all four proposals.","Route the residue: objections to you directly by Friday, off the thread. Then don't reply again."],"focus":["concision","impact"],"placeholder":"Decision: we adopt the alternating-week rota starting the 1st. It's the only option that worked for both depots' shift times."},
    {"id":"together-gov-early-22","level":"early","profession":"publicservice","title":"The self-assessment without fluff","scenario":"Annual review, and the self-assessment form sits open. The temptation runs both directions: the modesty that buries your best work ('assisted with various improvements') and the fluff that inflates it ('spearheaded transformational change'). The truth is better than both: you rebuilt the intake checklist and errors fell by half.","task":"Write two claims with their evidence, and one growth area stated plainly.","tips":["Each claim in the form: what you did, what changed, the number — 'rebuilt the intake checklist; form errors fell from 12 a week to 5.'","Your growth area stated as specifically as your wins — 'my radio reports run long under stress' beats 'communication'.","If a claim has no number or witness, either find one or cut the claim."],"focus":["precision","concision"],"placeholder":"I rebuilt the counter intake checklist in March; form errors fell from 12 a week to 5 and stayed there. I also took the Saturday coverage gap: 14 shifts this year, 11 of them on under-48-hours notice."},
    {"id":"together-gov-early-23","level":"early","profession":"publicservice","title":"The fourth email","scenario":"A resident's fourth email about his fence dispute has arrived, angrier than the third, now cc'ing the mayor. You've answered the core question three times — the fence is legal, and the file supports it. This reply must do three jobs at once: answer completely, set the boundary, and close the loop for the cc'd audience.","task":"Write the reply: the complete answer restated once, the boundary, the path that remains.","tips":["Write for the mayor's office reading over his shoulder — complete, calm, and final.","Restate the answer with its basis one full time, as if fresh — then say it is the office's final position.","The boundary is procedural, not personal: further correspondence on this matter will be added to the file; the appeal route is X, deadline Y."],"focus":["audience","impact"],"placeholder":"I'll restate the office's full answer so it's in one place: your neighbour's fence, at 1.9 metres, is within the 2.0-metre limit that applies to rear property lines, confirmed by measurement on two site visits."},
    {"id":"together-gov-early-24","level":"early","profession":"publicservice","title":"Sixty seconds to incoming command","scenario":"The duty chief is three minutes out from your working structure fire and wants the picture before arrival. Sixty seconds of radio: situation, resources committed, the two risks, and the one decision waiting for them. Everything the course taught, compressed into the tightest channel you use.","task":"Give the 60-second brief in that order, spoken, no wasted words.","tips":["Fixed order under stress: situation, resources, risks, decision pending — fill the slots, don't compose.","Risks are the part they can't see from the road: the propane tank on side C, the hydrant pressure dropping.","End on the decision waiting for them — that's what makes the brief theirs and not just yours."],"focus":["structure","concision"]},
    {"id":"together-gov-early-25","level":"early","profession":"publicservice","title":"The send-ready pass","scenario":"Your draft to the division director covers the counter backlog, the fix you've piloted, and the funding it needs — and it's currently 400 unstructured words. Before sending: run the whole checklist. Point first? Structured? Cut to the bone? Numbers precise? Fitted to a director's altitude? One pass, every module.","task":"Write the send version's opening 3 sentences after the full edit.","tips":["The director's question is 'what do you need from me and why' — the entire email serves that.","One number per claim, each one checkable; delete every adjective doing a number's job.","Final test before sending: if she reads only sentence one, does the right thing still happen?"],"focus":["clarity","structure"],"placeholder":"I'm asking for $9,000 to extend the intake pilot that has already cut our counter backlog by a third. The pilot ran four weeks at one station: waits fell from 34 minutes to 12, and the backlog dropped from 220 files to 145."}
  ],
};
